// ============================================================
// n8n Code Node: XML to Qargo Order JSON Mapper
// XML from: Qargo XML
// Output: one Qargo order payload per order
// No raw_input / no document included
// ============================================================

const safeGet = (obj, path, fallback = null) => {
	try {
		const value = path.split('.').reduce((acc, key) => acc?.[key], obj);
		if (value === undefined || value === null || value === '') {
			return fallback;
		}
		return typeof value === 'string' ? value.trim() : value;
	} catch (e) {
		return fallback;
	}
};

const formatDate = (dateValue) => {
	if (!dateValue) return null;
	try {
		const date = new Date(dateValue);
		if (isNaN(date.getTime())) return dateValue;
		return date.toISOString().split('T')[0];
	} catch (e) {
		return dateValue;
	}
};

const mapTemperature = (rawTemp) => {
	if (!rawTemp) return 'Ambient ( Geen Temp)';
	const str = String(rawTemp).trim();
	const match = str.match(/-?\d+(\.\d+)?/);
	if (!match) return 'Ambient ( Geen Temp)';
	const temp = parseFloat(match[0]);

	if (temp <= -18) return 'Frozen (-18°C / -30°C)';
	if (temp >= 0 && temp <= 3) return 'Ultra Fresh (0°C / 3°C)';
	if (temp >= 4 && temp <= 7) return 'Fresh (4°C / 7°C)';
	if (temp >= 8 && temp <= 20) return 'Thermo (8°C / 20°C)';
	return 'Ambient ( Geen Temp)';
};

const mapPackaging = (raw) => {
	if (!raw) return '';
	const key = String(raw).trim().toUpperCase();
	const map = {
		'BLOK': 'BLOK',
		'BLOK XL': 'BLOK XL',
		'CBL 11': 'CBL 11',
		'CBL 17': 'CBL 17',
		'CONTRA LOAD BOX': 'Contra load Box',
		'CONTRA LOAD': 'Contra load Box',
		'CHEP': 'CHEP',
		'DOLAV': 'DOLAV',
		'EURO': 'EURO',
		'H1': 'H1',
		'ONEWAY': 'ONEWAY ( Eenmalige pallet)',
		'EENMALIGE PALLET': 'ONEWAY ( Eenmalige pallet)',
	};
	return map[key] || raw;
};

// ── XML uit Qargo XML ───────────────────────────────────────
const input = $('Qargo XML').first().json;

const root =
	input?.VFPData ||
	input?.vfpdata ||
	input?.root ||
	input?.Root ||
	input?.data ||
	input?.Data ||
	input;

const rawRows =
	root?.query ||
	root?.Query ||
	root?.row ||
	root?.Row ||
	root?.record ||
	root?.Record ||
	[];

const rows = Array.isArray(rawRows) ? rawRows : [rawRows];

if (!rows || rows.length === 0 || !rows[0]) {
	throw new Error('No query rows found in XML node output');
}

const buildGoodsItems = (rows) => {
	const first = rows[0];
	const totalCap = parseFloat(safeGet(first, 'c9_ap', 0));
	const totalRows = rows.length;

	if (totalRows > totalCap) {
		const combinedDesc = rows
			.map(r => [safeGet(r, 'art_code', ''), safeGet(r, 'art_desc1', '')].filter(Boolean).join(' '))
			.filter(Boolean)
			.join(' | ');

		const totalWeight = rows.reduce(
			(sum, r) => sum + parseFloat(safeGet(r, 'ord_qty', 0) || 0),
			0
		);

		const totalColli = rows.reduce(
			(sum, r) => sum + parseInt(safeGet(r, 'tot_colli', 0) || 0, 10),
			0
		);

		const rawTemp = safeGet(first, 'article_comment1') || safeGet(first, 'so_dtl_temperature');
		const mappedTemp = mapTemperature(rawTemp);
		const rawPkg = safeGet(first, 'c9_tpl', '');
		const mappedPkg = mapPackaging(rawPkg);

		return [{
			quantity: totalCap,
			description: combinedDesc,
			total_weight_kg: totalWeight,
			packaging_type: {
				name: mappedPkg,
				packaging_size: { name: mappedPkg }
			},
			custom_fields: {
				colli: totalColli,
				temperature1: mappedTemp
			}
		}];
	}

	return rows.map((row, index) => {
		const rawTemp = safeGet(row, 'article_comment1') || safeGet(row, 'so_dtl_temperature');
		const mappedTemp = mapTemperature(rawTemp);
		const rawPkg = safeGet(row, 'c9_tpl', '');
		const mappedPkg = mapPackaging(rawPkg);

		const quantity = index === 0 ? totalCap - (totalRows - 1) : 1;

		return {
			quantity,
			description: [safeGet(row, 'art_code', ''), safeGet(row, 'art_desc1', '')].filter(Boolean).join(' '),
			Total_weight_kg: parseFloat(safeGet(row, 'ord_qty', 0) || 0),
			packaging_type: {
				name: mappedPkg,
				packaging_size: { name: mappedPkg }
			},
			custom_fields: {
				colli: parseInt(safeGet(row, 'tot_colli', 0) || 0, 10),
				temperature1: mappedTemp
			}
		};
	});
};

const buildOrder = (orderNr, rows) => {
	const first = rows[0];

	return {
		transport_service: {
			name: 'Transport',
			code: '1'
		},
		transport_network: {
			name: 'Agro World'
		},
		customer_reference_number: safeGet(first, 'so_hdr_ord_nr', ''),
		neutral_order_type: 'NO_NEUTRAL_ORDER',
		operation: 'CREATE',
		order_identifier: safeGet(first, 'so_hdr_ord_nr', ''),
		customer: {
			name: 'FN Global Meat'
		},
		consignments: [
			{
				pickup_stop: {
					activity_label: 'PICKUP',
					note: safeGet(first, 'c9_lco', '') || safeGet(first, 'c9_comment', ''),
					date: formatDate(safeGet(first, 'c9_load', '')),
					reference_number: safeGet(first, 'c9_rn', ''),
					location: {
						address: '',
						city: '',
						country: '',
						postal_code: '',
						name: safeGet(first, 'c9_coldoms', '')
					}
				},
				delivery_stop: {
					activity_label: 'DELIVERY',
					note: safeGet(first, 'c9_lco', ''),
					date: formatDate(safeGet(first, 'c9_unload', '')),
					reference_number: safeGet(first, 'c9_rn', ''),
					location: {
						address: safeGet(first, 'address1', ''),
						city: safeGet(first, 'city', ''),
						country: safeGet(first, 'country', ''),
						postal_code: safeGet(first, 'post_code', ''),
						name: safeGet(first, 'c9_invacct', '')
					}
				},
				goods: buildGoodsItems(rows)
			}
		]
	};
};

const grouped = {};
for (const row of rows) {
	const orderNr = safeGet(row, 'so_hdr_ord_nr', 'UNKNOWN');
	if (!grouped[orderNr]) grouped[orderNr] = [];
	grouped[orderNr].push(row);
}

const orderKeys = Object.keys(grouped);

return orderKeys.map((nr) => {
	const payload = buildOrder(nr, grouped[nr]);
	return {
		json: payload
	};
});

