// This node can only generate code for data transformation based on provided input and schema.
// It cannot control or optimize the input from the code.
return $input.all();

// n8n Code Node: EKRO XLSX to Qargo Order JSON Mapper
// Input: merged data from previous node(s)
// Output: one Qargo order payload per orderregel
//
// Regels:
// - customer = Ekro
// - temperatuur wordt bepaald op basis van:
//   * "Verladen: ..." tekst in Excel (heeft voorrang)
//   * sheetname als fallback
//   * Grolleman => Frozen
//   * Ekro => Fresh
//   * ESA => Ultra Fresh
// - pickup date komt uit rij met "Verladingen dd-mm-yyyy"
// - pickup location name komt uit rij met "Verladen: ..."
// - elke orderregel + delivery-regel eronder = 1 aparte order
// - quantity komt uit delivery-regel, bv /2 pallets/
// - packaging_type komt uit delivery-regel, bv Pallet
// - goods.description blijft alleen de delivery_name
// - custom_fields.colli blijft uit Excel kolom __EMPTY_8
// - truck_reference mag gelijk zijn voor meerdere orders
// - email_id wordt meegenomen voor Move Email node
// - pairedItem wordt meegegeven zodat volgende nodes geen paired item error geven
// ============================================================

const inputItems = $input.all();
const rows = inputItems.map(item => item.json);

if (!rows.length) {
	throw new Error('No input rows received');
}

const safeGet = (obj, path, fallback = null) => {
	try {
		const value = path.split('.').reduce((acc, key) => acc?.[key], obj);
		if (value === undefined || value === null || value === '') {
			return fallback;
		}
		return typeof value === 'string' ? value.trim() : value;
	} catch (e) {
		return fallback;
	}
};

const formatDate = (dateValue) => {
	if (!dateValue) return null;
	try {
		const date = new Date(dateValue);
		if (isNaN(date.getTime())) return dateValue;
		return date.toISOString().split('T')[0];
	} catch (e) {
		return dateValue;
	}
};

const parseDashDate = (text) => {
	if (!text) return null;
	const match = String(text).match(/(\d{2})-(\d{2})-(\d{4})/);
	if (!match) return null;
	const [, dd, mm, yyyy] = match;
	return `${yyyy}-${mm}-${dd}`;
};

const parseSlashDate = (text) => {
	if (!text) return null;
	const match = String(text).match(/(\d{2})\/(\d{2})\/(\d{4})/);
	if (!match) return null;
	const [, dd, mm, yyyy] = match;
	return `${yyyy}-${mm}-${dd}`;
};

const toNumber = (value, fallback = 0) => {
	if (value === undefined || value === null || value === '') return fallback;
	const n = parseFloat(String(value).replace(',', '.'));
	return Number.isFinite(n) ? n : fallback;
};

const normalizePackagingName = (raw) => {
	if (!raw) return '';

	let value = String(raw).trim().toLowerCase();

	value = value
		.replace(/[-–].*$/, '')
		.replace(/\b(bevroren|bveroren|gekoeld|fresh|frozen|transport)\b.*$/i, '')
		.replace(/\s{2,}/g, ' ')
		.trim();

	const map = {
		pallet: 'Pallet',
		pallets: 'Pallet',
		pal: 'Pallet',
		euro: 'Euro',
		eur: 'Euro',
		ep: 'Euro',
		blok: 'Block',
		block: 'Block',
		blocks: 'Block',
		ewp: 'EWP',
		wegwerp: 'Wegwerp',
		hang: 'Hang',
		doos: 'Doos',
		dozen: 'Doos',
		karton: 'Doos',
		krat: 'Krat',
		kratten: 'Krat'
	};

	return map[value] || '';
};

const parseDeliveryInfo = (text) => {
	if (!text) {
		return {
			note: '',
			deliveryDate: null,
			packagingQuantity: null,
			packagingName: ''
		};
	}

	const value = String(text).trim();

	const dateMatch = value.match(/(\d{2}\/\d{2}\/\d{4})/);
	const deliveryDate = dateMatch ? parseSlashDate(dateMatch[1]) : null;

	const slashMatch = value.match(/\/\s*([^\/]+?)\s*\/+/i);

	let packagingQuantity = null;
	let packagingName = '';

	if (slashMatch?.[1]) {
		let insideSlashes = slashMatch[1]
			.replace(/\s{2,}/g, ' ')
			.trim();

		insideSlashes = insideSlashes.replace(/[-–].*$/, '').trim();

		const qtyPackMatch = insideSlashes.match(/^(\d+(?:[.,]\d+)?)\s+(.+)$/i);

		if (qtyPackMatch) {
			const qtyRaw = String(qtyPackMatch[1]).replace(',', '.');
			const packRaw = String(qtyPackMatch[2]).trim();

			const qty = parseFloat(qtyRaw);
			packagingQuantity = Number.isFinite(qty) ? Math.round(qty) : null;
			packagingName = normalizePackagingName(packRaw);
		}
	}

	return {
		note: value,
		deliveryDate,
		packagingQuantity,
		packagingName
	};
};

// ── temperatuur detectie (sheet + verladen tekst) ───────────
const normalizeName = (value) => {
	return String(value || '')
		.toLowerCase()
		.replace(/\./g, '')
		.replace(/\s+/g, '')
		.trim();
};

const detectTemperature = (text) => {
	const normalized = normalizeName(text);

	if (normalized.includes('grolleman')) {
		return 'Frozen (-18°C / -30°C)';
	}
	if (normalized.includes('esa')) {
		return 'Ultra Fresh (0°C / 3°C)';
	}
	if (normalized.includes('ekro')) {
		return 'Fresh (4°C / 7°C)';
	}

	return '';
};

// ── mail metadata uit upstream proberen te halen ────────────
const firstInput = rows[0] || {};

const bodyPreview = String(
	firstInput.bodyPreview ||
	firstInput.mail_bodyPreview ||
	''
);

const bodyHtml = String(
	firstInput.body?.content ||
	firstInput.bodyHtml ||
	firstInput.mail_bodyHtml ||
	''
);

const upstreamOriginalSender = String(
	firstInput.original_sender ||
	firstInput.senderEmail ||
	firstInput.sender_address ||
	firstInput.from_address ||
	firstInput.message_sender ||
	''
).toLowerCase();

const previewVanMatch = bodyPreview.match(/Van:\s.*?<([^>]+)>/i);
const htmlVanMatch = bodyHtml.match(/Van:\s.*?&lt;([^&]+)&gt;/i);
const previewGenericMatch = bodyPreview.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/i);
const htmlGenericMatch = bodyHtml.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/i);

const originalSender = String(
	upstreamOriginalSender ||
	previewVanMatch?.[1] ||
	htmlVanMatch?.[1] ||
	previewGenericMatch?.[0] ||
	htmlGenericMatch?.[0] ||
	''
).toLowerCase();

const emailId =
	firstInput.email_id ||
	firstInput.message_id ||
	firstInput.id ||
	'';

// ── customer vast op Ekro voor deze workflow ────────────────
const customerName = 'Ekro';

// ── eerst sheetnaam als fallback gebruiken ──────────────────
const rawSheetName =
	firstInput.sheetName ||
	firstInput.sheet_name ||
	firstInput.tabName ||
	firstInput.tab_name ||
	firstInput.worksheet ||
	firstInput.worksheetName ||
	'';

let transportTemperature = detectTemperature(rawSheetName);

// ── XLSX regels parsen ──────────────────────────────────────
const parsedRows = [];
let currentPickupDate = null;
let currentPickupName = '';

for (let i = 0; i < rows.length; i++) {
	const row = rows[i] || {};
	const nextRow = rows[i + 1] || {};

	const col0 = String(safeGet(row, '__EMPTY', '') || '').trim();
	const col1 = String(safeGet(row, '__EMPTY_1', '') || '').trim();
	const col3 = String(safeGet(row, '__EMPTY_3', '') || '').trim();
	const col4 = String(safeGet(row, '__EMPTY_4', '') || '').trim();
	const col5 = String(safeGet(row, '__EMPTY_5', '') || '').trim();
	const col6 = String(safeGet(row, '__EMPTY_6', '') || '').trim();
	const col7 = String(safeGet(row, '__EMPTY_7', '') || '').trim();
	const col8 = safeGet(row, '__EMPTY_8', '');
	const col9 = safeGet(row, '__EMPTY_9', '');
	const col11 = String(safeGet(row, '__EMPTY_11', '') || '').trim();
	const col13 = String(safeGet(row, '__EMPTY_13', '') || '').trim();

	const lowerCol0 = col0.toLowerCase();
	const lowerCol1 = col1.toLowerCase();
	const lowerCol3 = col3.toLowerCase();

	// Pickup datum uit "Verladingen dd-mm-yyyy"
	if (lowerCol0.startsWith('verladingen')) {
		currentPickupDate = parseDashDate(col0);
		continue;
	}

	// Soms staat die datum in kolom 6
	if (!currentPickupDate && col6) {
		const parsedDate = parseDashDate(col6);
		if (parsedDate) {
			currentPickupDate = parsedDate;
		}
	}

	// Pickup name uit __EMPTY + temperatuur bepalen
	if (lowerCol0.startsWith('verladen:')) {
		currentPickupName = col0.replace(/^verladen:\s*/i, '').trim();

		const detectedTemp = detectTemperature(currentPickupName);
		if (detectedTemp) {
			transportTemperature = detectedTemp;
		}

		continue;
	}

	// fallback pickup name uit __EMPTY_1 + temperatuur bepalen
	if (lowerCol1.startsWith('verladen:')) {
		currentPickupName = col1.replace(/^verladen:\s*/i, '').trim();

		const detectedTemp = detectTemperature(currentPickupName);
		if (detectedTemp) {
			transportTemperature = detectedTemp;
		}

		continue;
	}

	const headers = [
		'overslag',
		'losadres',
		'postcode',
		'woonplaats',
		'verp.',
		'verp',
		'colli',
		'gewicht',
		'reference',
		'truck reference'
	];

	if (headers.includes(lowerCol0) || headers.includes(lowerCol1) || headers.includes(lowerCol3)) {
		continue;
	}

	// pure delivery-regel zelf overslaan, die wordt op orderregel eronder/erboven meegelezen
	if (lowerCol1.startsWith('delivery') || lowerCol0.startsWith('delivery')) {
		continue;
	}

	const colli = toNumber(col8, 0);
	const gewicht = toNumber(col9, 0);

	if (!col1 && !col3 && !col4 && !col5 && (colli > 0 || gewicht > 0)) {
		continue;
	}

	const isOrderRow = !!col1 && (colli > 0 || gewicht > 0);
	if (!isOrderRow) {
		continue;
	}

	const nextText = String(
		safeGet(nextRow, '__EMPTY_1', '') ||
		safeGet(nextRow, '__EMPTY', '') ||
		''
	).trim();

	const deliveryInfo = nextText.toLowerCase().includes('delivery')
		? parseDeliveryInfo(nextText)
		: {
			note: '',
			deliveryDate: null,
			packagingQuantity: null,
			packagingName: ''
		};

	parsedRows.push({
		sourceIndex: i,
		email_id: safeGet(row, 'email_id', emailId),
		orderNr: col13 || col11 || col1,
		customer_reference_number: col11,
		truck_reference: col13,
		pickup_name: currentPickupName,
		pickup_date: currentPickupDate,
		delivery_name: col1,
		address1: col3,
		post_code: col4,
		city: col5,
		tot_colli: colli,
		ord_qty: gewicht,
		note: deliveryInfo.note,
		delivery_date: deliveryInfo.deliveryDate,
		packaging_quantity: deliveryInfo.packagingQuantity,
		packaging_name: deliveryInfo.packagingName || normalizePackagingName(col7) || '',
		customer_name: customerName,
		transport_temperature: transportTemperature,
		original_sender: originalSender
	});
}

if (!parsedRows.length) {
	throw new Error('No parsed order rows found in XLSX node output');
}

// ── Per row exact 1 goods item ──────────────────────────────
const buildGoodsItem = (row) => {
	const packagingName =
		safeGet(row, 'packaging_name', '') ||
		'Pallet';

	const quantity =
		parseInt(safeGet(row, 'packaging_quantity', 0) || 0, 10) ||
		1;

	const colli =
		parseInt(safeGet(row, 'tot_colli', 0) || 0, 10) ||
		0;

	const unitWeightKg =
		parseFloat(safeGet(row, 'ord_qty', 0) || 0) ||
		0;

	const goods = {
		quantity: quantity,
		description: safeGet(row, 'delivery_name', ''),
		total_weight_kg: unitWeightKg,
		packaging_type: {
			name: packagingName,
			packaging_size: {
				name: packagingName
			}
		},
		custom_fields: {
			colli: colli
		}
	};

	if (safeGet(row, 'transport_temperature', '')) {
		goods.custom_fields.temperature1 = safeGet(row, 'transport_temperature', '');
	}

	return goods;
};

// ── Per row exact 1 order ───────────────────────────────────
const buildOrder = (row, index) => {
	const customerRef = safeGet(row, 'customer_reference_number', '');
	const truckRef = safeGet(row, 'truck_reference', '');
	const deliveryName = safeGet(row, 'delivery_name', '');

	const orderIdentifierBase =
		truckRef || customerRef || deliveryName || `ORDER_${index + 1}`;

	const uniqueOrderIdentifier = `${orderIdentifierBase}_${index + 1}`;

	return {
		transport_service: {
			name: 'Transport',
			code: '1'
		},
		transport_network: {
			name: 'Agro World'
		},
		customer_reference_number: customerRef,
		truck_reference: truckRef,
		neutral_order_type: 'NO_NEUTRAL_ORDER',
		operation: 'CREATE',
		order_identifier: uniqueOrderIdentifier,
		customer: {
			name: safeGet(row, 'customer_name', 'Ekro')
		},
		consignments: [
			{
				pickup_stop: {
					activity_label: 'PICKUP',
					note: '',
					date: formatDate(safeGet(row, 'pickup_date', '')),
					reference_number: truckRef,
					location: {
						address: '',
						city: '',
						country: '',
						postal_code: '',
						name: safeGet(row, 'pickup_name', '')
					}
				},
				delivery_stop: {
					activity_label: 'DELIVERY',
					note: safeGet(row, 'note', ''),
					date: formatDate(
						safeGet(row, 'delivery_date', '') ||
						safeGet(row, 'pickup_date', '')
					),
					reference_number: truckRef,
					location: {
						address: safeGet(row, 'address1', ''),
						city: safeGet(row, 'city', ''),
						country: '',
						postal_code: safeGet(row, 'post_code', ''),
						name: deliveryName
					}
				},
				goods: [buildGoodsItem(row)]
			}
		]
	};
};

return parsedRows.map((row, index) => ({
	json: {
		...buildOrder(row, index),
		email_id: safeGet(row, 'email_id', '')
	},
	pairedItem: {
		item: row.sourceIndex
	}
}));

