// ============================================================
// n8n Code Node: Tönnies XLSX -> Qargo Order JSON Mapper
// V8.0.6 — Production (TK→Frozen fix)
// Scope: Tönnies Convenience / Tönnies Lebensmittel / Weidemark
// (and Tönnies group siblings) — packaging always EURO.
//
// Rules enforced:
//   * 1 KommNr = 1 order = 1 consignment
//   * Within 1 KommNr: goods geconsolideerd op (description + temperature)
//       -> zelfde omschrijving = 1 good (quantity + weight opgeteld)
//       -> andere omschrijving = aparte good
//   * Dubbele rijen uit de XLSX vallen hierdoor automatisch samen
//   * Tour in pickup_stop.note
//   * Storno => operation DELETE, else CREATE
//   * Recursive cleanup van null / undefined / "" / {} / []
// ============================================================

const rows = $input.all().map(i => i.json);
if (!rows.length) throw new Error('No input rows received');

// ---------- primitive helpers ----------
const txt = (v) => (v === null || v === undefined) ? '' : String(v).trim();

const num = (v) => {
  const s = txt(v);
  if (!s) return 0;
  const n = Number(s.replace(/\s/g, '').replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
};

const dateFmt = (v) => {
  const s = txt(v);
  if (!s) return '';
  let m = s.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;
  m = s.match(/^(\d{2})-(\d{2})-(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;
  m = s.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (m) return s;
  return s;
};

const mapTemp = (v) => {
  const s = txt(v).toLowerCase();
  if (!s) return 'Ambient (Geen Temp)';
  // Frozen FIRST (TK / Tiefkühl / tiefgefroren / frozen)
  if (/\btk\b/.test(s) || s.includes('tk-ware') || s.includes('tiefkühl') ||
      s.includes('tiefkuhl') || s.includes('tiefgefroren') || s.includes('frozen')) {
    return 'Frozen (-18°C / -30°C)';
  }
  if (s.includes('ultrafrisch')) return 'Ultra Fresh (0°C / 3°C)';
  if (s.includes('frisch'))      return 'Fresh (4°C / 7°C)';
  return 'Ambient (Geen Temp)';
};

const isStorno = (v) => txt(v).toLowerCase().includes('storno');

const isMeaningfulRef = (v) => {
  const s = txt(v).toLowerCase();
  if (!s) return false;
  return !['-', 'x', 'xx', 'xxx'].includes(s);
};

const getPickup = (kommNr, belOrt, rechnungAn) => {
  const prefix = txt(kommNr).slice(0, 4);
  if (prefix === '1000') return { name: 'Tönnies Lebensmittel', city: txt(belOrt) || 'Rheda-Wiedenbrück', customer: 'Tönnies Lebensmittel' };
  if (prefix === '1005') return { name: 'Weidemark Sögel',       city: txt(belOrt) || 'Sögel',              customer: 'Weidemark' };
  if (prefix === '2000') return { name: 'Tönnies Rind',           city: txt(belOrt) || 'Badbergen',          customer: 'Tönnies Rind' };
  if (prefix === '3000') return { name: 'Tillman Convenience',    city: txt(belOrt) || 'Rheda-Wiedenbrück', customer: 'Tillman Convenience' };
  if (prefix === '4000') return { name: 'Tönnies Convenience',    city: txt(belOrt) || 'Rheda-Wiedenbrück', customer: 'Tönnies Convenience' };
  return { name: txt(rechnungAn) || 'Tönnies', city: txt(belOrt), customer: txt(rechnungAn) || 'Tönnies' };
};

// Recursive cleanup: strip null / undefined / '' / {} / []
function clean(value) {
  if (value === null || value === undefined) return undefined;
  if (typeof value === 'string') return value.trim() === '' ? undefined : value;
  if (Array.isArray(value)) {
    const arr = value.map(clean).filter(v => v !== undefined);
    return arr.length ? arr : undefined;
  }
  if (typeof value === 'object') {
    const out = {};
    for (const k of Object.keys(value)) {
      const c = clean(value[k]);
      if (c !== undefined) out[k] = c;
    }
    return Object.keys(out).length ? out : undefined;
  }
  return value;
}

// ---------- group rows per KommNr ----------
const grouped = {};
const orderSequence = [];

for (let i = 0; i < rows.length; i++) {
  const row = rows[i];
  const kommNr = txt(row['KommNr']);
  if (!kommNr) continue;

  const pickup = getPickup(kommNr, row['BelOrt'], row['Rechnung an']);
  const postCode = txt(row['EmpfängerPLZ']).replace(/\.0$/, '');
  const country = /^\d{4}$/.test(postCode) ? 'DK' : 'DE';

  const parsed = {
    sourceIndex: i,
    kommNr,
    customer_name: txt(row['Rechnung an']) || pickup.customer,
    externeBelegnr: txt(row['Externe_Belegnr.'] || row['Externe_Belegnr']),
    pickup_name: pickup.name,
    pickup_city: pickup.city,
    pickup_date: dateFmt(row['BelVonDat']),
    delivery_name: txt(row['EmpName1']),
    address1: txt(row['Strasse']),
    post_code: postCode,
    country,
    city: txt(row['EmpOrt']),
    quantity: num(row['Pal. Anzahl']),
    weight: num(row['TatsGew']),
    artikelmerkmal: txt(row['Artikelmerkmal']),
    temperature: mapTemp(row['Artikelmerkmal']),
    note: txt(row['Bemerkung']),
    is_storno: isStorno(row['Bemerkung']),
    delivery_date: dateFmt(row['EntBisDat']),
    delivery_time: txt(row['EntBisZeit']),
    tour: txt(row['Tour'])
  };

  if (!grouped[kommNr]) {
    grouped[kommNr] = [];
    orderSequence.push(kommNr);
  }
  grouped[kommNr].push(parsed);
}

// ---------- build one order per KommNr ----------
const result = orderSequence.map((kommNr) => {
  const orderRows = grouped[kommNr];
  const first = orderRows[0];

  const descriptions = [...new Set(orderRows.map(r => r.artikelmerkmal).filter(Boolean))];
  const externeRefs  = [...new Set(orderRows.map(r => r.externeBelegnr).filter(isMeaningfulRef))];
  const tours        = [...new Set(orderRows.map(r => r.tour).filter(Boolean))];
  const temps        = [...new Set(orderRows.map(r => r.temperature).filter(Boolean))];

  const operation = orderRows.some(r => r.is_storno) ? 'DELETE' : 'CREATE';

  // Consolidatie: zelfde (description + temperature) binnen 1 KommNr -> 1 good
  const goodsMap = new Map();
  for (const row of orderRows) {
    const description = row.artikelmerkmal || descriptions.join(' / ') || 'Goods';
    const temperature = row.temperature || 'Ambient (Geen Temp)';
    const key = `${description.toLowerCase()}||${temperature}`;

    const qty = row.quantity > 0 ? row.quantity : 1;
    const wgt = row.weight   > 0 ? row.weight   : 0;

    const existing = goodsMap.get(key);
    if (existing) {
      existing.quantity        += qty;
      existing.total_weight_kg += wgt;
    } else {
      goodsMap.set(key, {
        quantity: qty,
        description,
        total_weight_kg: wgt,
        packaging_type: { name: 'EURO' },
        custom_fields: { temperature1: temperature }
      });
    }
  }

  const goods = [...goodsMap.values()].map(g => ({
    ...g,
    total_weight_kg: Number(g.total_weight_kg.toFixed(2))
  }));

  const pickupNotes = [];
  if (tours.length) pickupNotes.push(`Tour: ${tours.join(', ')}`);

  const deliveryNotes = [];
  if (first.delivery_time) deliveryNotes.push(`Lostijd: ${first.delivery_time}`);
  if (first.note)           deliveryNotes.push(first.note);
  if (temps.length)         deliveryNotes.push(`Temperatuur: ${temps.join(', ')}`);

  const order = {
    transport_service: { name: 'Transport', code: '1' },
    transport_network: { name: 'Agro World' },
    customer_reference_number: externeRefs.join(', ') || kommNr,
    neutral_order_type: 'NO_NEUTRAL_ORDER',
    operation,
    order_identifier: kommNr,
    customer: { name: first.customer_name },
    consignments: [
      {
        pickup_stop: {
          activity_label: 'PICKUP',
          note: pickupNotes.join(' | '),
          date: first.pickup_date,
          reference_number: kommNr,
          location: {
            city: first.pickup_city,
            country: 'DE',
            name: first.pickup_name
          }
        },
        delivery_stop: {
          activity_label: 'DELIVERY',
          note: deliveryNotes.join(' | '),
          date: first.delivery_date,
          reference_number: externeRefs.join(', ') || kommNr,
          location: {
            address: first.address1,
            city: first.city,
            country: first.country,
            postal_code: first.post_code,
            name: first.delivery_name
          }
        },
        goods
      }
    ]
  };

  return {
    json: clean(order),
    pairedItem: { item: first.sourceIndex }
  };
});

return result;

// This node can only generate code for data transformation based on provided input and schema.
// It cannot control or optimize the input from the code or check if all data is correct.
// However, it can return the input data as it is.
return $input.all();

// ============================================================
// n8n Code node
// Coomans XLS -> Qargo order payload
// Input comes from previous node / Merge
// Standard quantity distribution:
//   total pallets 11 + 3 goods => 9, 1, 1
// customer_id = reference_number op delivery_stop
// pallets = quantity per goods
// total_weight_kg hoort onder goods
// total_boxes = custom_fields.colli per goods
// ============================================================

// ---------- Input ----------
const rows = $input.all().map(item => item.json);

// ---------- Helpers ----------
const val = (row, key) => {
	const v = row?.[key];
	return v === undefined || v === null ? '' : String(v).trim();
};

const findRow = (predicate) => rows.find(predicate);
const findRowIndex = (predicate) => rows.findIndex(predicate);

const getLabelValue = (label) => {
	const row = findRow(r => val(r, '__EMPTY_13') === label);
	if (!row) return '';
	return val(row, '__EMPTY_16') || val(row, '__EMPTY_14') || '';
};

const intFromText = (input) => {
	const n = parseInt(String(input || '').replace(/[^\d-]/g, ''), 10);
	return Number.isNaN(n) ? 0 : n;
};

const numberKgFromText = (input) => {
	const str = String(input || '')
		.replace(/\./g, '')
		.replace(',', '.')
		.replace(/[^\d.-]/g, '');
	const n = parseFloat(str);
	return Number.isNaN(n) ? 0 : n;
};

const excelDateToISO = (serial) => {
	if (serial === undefined || serial === null || serial === '') return null;

	if (typeof serial === 'string' && isNaN(Number(serial))) {
		const d = new Date(serial);
		return isNaN(d.getTime()) ? null : d.toISOString().split('T')[0];
	}

	const s = Number(serial);
	if (Number.isNaN(s)) return null;

	const utcDays = Math.floor(s - 25569);
	const utcValue = utcDays * 86400;
	const dateInfo = new Date(utcValue * 1000);

	return new Date(Date.UTC(
		dateInfo.getUTCFullYear(),
		dateInfo.getUTCMonth(),
		dateInfo.getUTCDate()
	)).toISOString().split('T')[0];
};

const parsePostalCity = (text) => {
	const str = String(text || '').trim();
	if (!str) {
		return { postal_code: '', city: '' };
	}

	const match = str.match(/^([0-9A-Z]{4,}\s?[A-Z]{0,2})\s+(.+)$/i);
	if (match) {
		return {
			postal_code: match[1].trim(),
			city: match[2].trim(),
		};
	}

	return {
		postal_code: '',
		city: str,
	};
};

const mapTemperature = (text) => {
	const str = String(text || '');

	const range = str.match(/(-?\d+)\s*\/\s*\+?(-?\d+)/);
	if (range) {
		const min = parseFloat(range[1]);
		const max = parseFloat(range[2]);

		if (min <= -18 || max <= -18) return 'Frozen (-18°C / -30°C)';
		if (min >= -1 && max <= 1) return 'Ultra Fresh (0°C / 3°C)';
		if (min >= 0 && max <= 3) return 'Ultra Fresh (0°C / 3°C)';
		if (min >= 4 && max <= 7) return 'Fresh (4°C / 7°C)';
		if (min >= 8 && max <= 20) return 'Thermo (8°C / 20°C)';
	}

	const single = str.match(/-?\d+(\.\d+)?/);
	if (!single) return 'Ambient ( Geen Temp)';

	const temp = parseFloat(single[0]);
	if (temp <= -18) return 'Frozen (-18°C / -30°C)';
	if (temp >= -1 && temp <= 1) return 'Ultra Fresh (0°C / 3°C)';
	if (temp >= 0 && temp <= 3) return 'Ultra Fresh (0°C / 3°C)';
	if (temp >= 4 && temp <= 7) return 'Fresh (4°C / 7°C)';
	if (temp >= 8 && temp <= 20) return 'Thermo (8°C / 20°C)';
	return 'Ambient ( Geen Temp)';
};

// Standard quantity distribution
const getDistributedQuantity = (totalQuantity, index, totalItems) => {
	const qty = parseInt(totalQuantity || 0, 10);

	if (!qty || qty <= 0) {
		return index === 0 ? 1 : 0;
	}

	if (totalItems <= 1) {
		return qty;
	}

	if (qty >= totalItems) {
		return index === 0 ? qty - (totalItems - 1) : 1;
	}

	return index < qty ? 1 : 0;
};

// ---------- Header fields ----------
const customerId = getLabelValue('Customer ID:');
const customerReference = getLabelValue('Customer ref:');
const orderIdentifier = getLabelValue('Order no:');
const orderDate = excelDateToISO(getLabelValue('Order date:'));
const transporter = getLabelValue('Transporter:');
const contact = getLabelValue('Contact:');
const phone = getLabelValue('Phone:');
const email = getLabelValue('Email:');

// ---------- Dates ----------
const shipmentRow = findRow(r => val(r, '__EMPTY_1') === 'Shipment date:');
const shipmentDate = excelDateToISO(shipmentRow?.__EMPTY_3);
const deliveryDate = excelDateToISO(shipmentRow?.__EMPTY_15);

// ---------- Pallets ----------
const palletRow = findRow(r => val(r, '__EMPTY_1').includes('Aantal Pallets'));
const palletText = val(palletRow, '__EMPTY_1');
const palletCount = intFromText(palletText);

// ---------- Pickup ----------
const loadingHeaderIndex = findRowIndex(r => val(r, '__EMPTY_6') === 'Loading address');
const pickupLines = [];

if (loadingHeaderIndex >= 0) {
	for (let i = loadingHeaderIndex + 1; i < rows.length; i++) {
		const line = val(rows[i], '__EMPTY_6');
		if (!line) continue;
		if (line === 'Deliveryaddress:' || line === 'Transport:' || line === 'Article no.') break;
		pickupLines.push(line);
		if (pickupLines.length >= 5) break;
	}
}

const pickupName = pickupLines[0] || '';
const pickupAddress = pickupLines[1] || '';
const pickupPostalCity = pickupLines[2] || '';
const pickupCountry = pickupLines[3] || '';
const pickupParsed = parsePostalCity(pickupPostalCity);

// ---------- Delivery ----------
const deliveryHeaderIndex = findRowIndex(r => val(r, '__EMPTY_2') === 'Deliveryaddress:');
const deliveryLines = [];

if (deliveryHeaderIndex >= 0) {
	for (let i = deliveryHeaderIndex + 1; i < rows.length; i++) {
		const line = val(rows[i], '__EMPTY_2');
		if (!line) continue;
		if (line === 'Transport:' || line === 'Article no.') break;
		deliveryLines.push(line);
		if (deliveryLines.length >= 5) break;
	}
}

const deliveryName = deliveryLines[0] || '';
const deliveryAddress = deliveryLines[1] || '';
const deliveryPostalCity = deliveryLines[2] || '';
const deliveryCountry = deliveryLines[3] || '';
const deliveryParsed = parsePostalCity(deliveryPostalCity);

// ---------- Articles verzamelen ----------
const articleHeaderIndex = findRowIndex(
	r => val(r, '__EMPTY_1') === 'Article no.' && val(r, '__EMPTY_3') === 'Description'
);

const totalsIndex = findRowIndex(r => val(r, '__EMPTY_8').startsWith('Totals:'));

const articleRows = [];

if (articleHeaderIndex >= 0) {
	for (let i = articleHeaderIndex + 1; i < rows.length; i++) {
		if (totalsIndex >= 0 && i >= totalsIndex) break;

		const articleNo = val(rows[i], '__EMPTY_1');
		const description = val(rows[i], '__EMPTY_3');
		const boxes = val(rows[i], '__EMPTY_15');
		const quantityKg = val(rows[i], '__EMPTY_18');

		if (articleNo && description) {
			articleRows.push({
				articleNo,
				description,
				boxes,
				quantityKg,
			});
		}
	}
}

// ---------- Temperature ----------
const temperatureRow = findRow(r => val(r, '__EMPTY_1').includes('Temperatuur/Temperature'));
const temperatureText = val(temperatureRow, '__EMPTY_1');
const mappedTemperature = mapTemperature(temperatureText);

// ---------- Totals ----------
const totalsRow = findRow(r => val(r, '__EMPTY_8').startsWith('Totals:'));
const totalBoxes = totalsRow ? intFromText(totalsRow.__EMPTY_15) : 0;
const totalWeightKg = totalsRow ? numberKgFromText(totalsRow.__EMPTY_18) : 0;

// ---------- Goods bouwen ----------
const goods = articleRows
	.map((row, index) => {
		const quantity = getDistributedQuantity(palletCount, index, articleRows.length);
		if (quantity <= 0) return null;

		const rowBoxes = intFromText(row.boxes);
		const rowWeight = numberKgFromText(row.quantityKg);

		return {
			quantity,
			description: `${row.articleNo} ${row.description}`.trim(),
			total_weight_kg: rowWeight,
			packaging_type: {
				name: 'EURO',
				packaging_size: {
					name: 'EURO'
				}
			},
			custom_fields: {
				colli: rowBoxes,
				temperature1: mappedTemperature
			}
		};
	})
	.filter(Boolean);

// Fallback als er geen article weights zijn maar wel totaalgewicht
if (goods.length > 0) {
	const sumGoodsWeight = goods.reduce((sum, g) => sum + (Number(g.total_weight_kg) || 0), 0);

	if (sumGoodsWeight === 0 && totalWeightKg > 0) {
		const totalQty = goods.reduce((sum, g) => sum + (Number(g.quantity) || 0), 0) || 1;
		const unitWeight = totalWeightKg / totalQty;

		for (const g of goods) {
			g.total_weight_kg = Number((unitWeight * g.quantity).toFixed(2));
		}
	}
}

// Als colli per regel leeg is, maar totaal wel bekend, zet totaal alleen op eerste goods
if (goods.length > 0) {
	const sumColli = goods.reduce((sum, g) => sum + (Number(g.custom_fields?.colli) || 0), 0);

	if (sumColli === 0 && totalBoxes > 0) {
		goods[0].custom_fields.colli = totalBoxes;
	}
}

// ---------- Instructions ----------
const specialIdx = findRowIndex(r => val(r, '__EMPTY_1') === 'Speciale Instructies');
const specialInstructions = specialIdx >= 0 ? val(rows[specialIdx + 1], '__EMPTY_1') : '';

// ---------- Payload ----------
const payload = {
	transport_service: {
		name: 'Transport',
		code: '1'
	},
	transport_network: {
		name: 'Agro World'
	},
	customer_reference_number: customerReference || orderIdentifier,
	neutral_order_type: 'NO_NEUTRAL_ORDER',
	operation: 'CREATE',
	order_identifier: orderIdentifier,
	customer: {
		name: 'Coomans Trade Import BV'
	},
	consignments: [
		{
			pickup_stop: {
				activity_label: 'PICKUP',
				note: [
					orderDate ? `Order date: ${orderDate}` : '',
					contact ? `Contact: ${contact}` : '',
					phone ? `Phone: ${phone}` : '',
					email ? `Email: ${email}` : '',
					transporter ? `Transporter: ${transporter}` : '',
					specialInstructions || ''
				].filter(Boolean).join('\n'),
				date: shipmentDate,
				reference_number: orderIdentifier,
				location: {
					address: pickupAddress,
					city: pickupParsed.city,
					country: pickupCountry,
					postal_code: pickupParsed.postal_code,
					name: pickupName
				}
			},
			delivery_stop: {
				activity_label: 'DELIVERY',
				note: specialInstructions || '',
				date: deliveryDate,
				reference_number: customerId || customerReference || orderIdentifier,
				location: {
					address: deliveryAddress,
					city: deliveryParsed.city,
					country: deliveryCountry,
					postal_code: deliveryParsed.postal_code,
					name: deliveryName
				}
			},
			goods
		}
	]
};

return [{ json: payload }];

// This node can only generate code for data transformation based on provided input and schema.
// It cannot control or optimize the input from the code or check if all data is correct.
// However, it can return the input data as it is.
return $input.all();

// n8n Code Node: Mail / Attachment Router
// Gebruik na "Get many folder messages" of na "Get Attachments"
// Output:
// - behoudt alle bestaande velden
// - voegt routing velden toe
// - bepaalt customer_flow
// - bewaart message_id voor latere Move Email node
// - stuurt bestanden naar aparte routes per klant of bestandstype

const items = $input.all();

const normalize = (value) => String(value || '').trim();
const toLower = (value) => normalize(value).toLowerCase();

const getFileExtension = (fileName) => {
    const name = normalize(fileName);
    const match = name.match(/\.([a-z0-9]+)$/i);
    return match ? match[1].toLowerCase() : '';
};

const extractOriginalSender = ({
    bodyPreview,
    bodyHtml,
    fromAddr,
    senderAddr,
    toAddr,
    ccAddr,
    subject,
    fileName
}) => {
    const combinedText = [
        fromAddr,
        senderAddr,
        toAddr,
        ccAddr,
        subject,
        fileName,
        bodyPreview,
        bodyHtml
    ]
        .filter(Boolean)
        .join(' ');

    const previewVanMatch = bodyPreview.match(/van:\s.*?<([^>]+)>/i);
    const htmlVanMatch = bodyHtml.match(/van:\s.*?&lt;([^&]+)&gt;/i);
    const genericMatch = combinedText.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/i);

    return (
        previewVanMatch?.[1] ||
        htmlVanMatch?.[1] ||
        genericMatch?.[0] ||
        ''
    ).toLowerCase();
};

const detectCustomerFlow = ({
    fromAddr,
    senderAddr,
    originalSender,
    toAddr,
    ccAddr,
    subject,
    bodyPreview,
    bodyHtml,
    fileName,
    extension
}) => {
    const text = [
        fromAddr,
        senderAddr,
        originalSender,
        toAddr,
        ccAddr,
        subject,
        bodyPreview,
        bodyHtml,
        fileName
    ]
        .filter(Boolean)
        .join(' ')
        .toLowerCase();

    const isXml = extension === 'xml';
    const isXlsx = extension === 'xlsx';
    const isXls = extension === 'xls';
    const isExcel = isXlsx || isXls;
    const isPdf = extension === 'pdf';

    const isEkro =
        text.includes('@ekro.nl') ||
        text.includes('transport@ekro.nl') ||
        fileName.includes('laadlijst') ||
        fileName.includes('ekro');

    const isTonnies =
        text.includes('tönnies') ||
        text.includes('tonnies') ||
        text.includes('tevex') ||
        text.includes('weidemark') ||
        fileName.includes('tonnies') ||
        fileName.includes('toennies') ||
        fileName.includes('tönnies') ||
        fileName.includes('tevex') ||
        fileName.includes('weidemark');

    const isComans =
        text.includes('comans') ||
        text.includes('ctimport') ||
        fileName.includes('comans') ||
        fileName.includes('ctimport');

    const isFnGlobalMeat =
        isXml ||
        text.includes('fn global meat') ||
        fileName.includes('fn') ||
        fileName.includes('global meat');

    const isCarnimex =
        text.includes('@carnimex.nl') ||
