	try {
		const value = path.split('.').reduce((acc, key) => acc?.[key], obj);
		if (value === undefined || value === null || value === '') {
			return fallback;
		}
		return typeof value === 'string' ? value.trim() : value;
	} catch (e) {
		return fallback;
	}
};

const formatDate = (dateValue) => {
	if (!dateValue) return null;
	try {
		const date = new Date(dateValue);
		if (isNaN(date.getTime())) return dateValue;
		return date.toISOString().split('T')[0];
	} catch (e) {
		return dateValue;
	}
};

const mapTemperature = (rawTemp) => {
	if (!rawTemp) return 'Ambient ( Geen Temp)';
	const str = String(rawTemp).trim();
	const match = str.match(/-?\d+(\.\d+)?/);
	if (!match) return 'Ambient ( Geen Temp)';
	const temp = parseFloat(match[0]);

	if (temp <= -18) return 'Frozen (-18°C / -30°C)';
	if (temp >= 0 && temp <= 3) return 'Ultra Fresh (0°C / 3°C)';
	if (temp >= 4 && temp <= 7) return 'Fresh (4°C / 7°C)';
	if (temp >= 8 && temp <= 20) return 'Thermo (8°C / 20°C)';
	return 'Ambient ( Geen Temp)';
};

const mapPackaging = (raw) => {
	if (!raw) return '';
	const key = String(raw).trim().toUpperCase();
	const map = {
		'BLOK': 'BLOK',
		'BLOK XL': 'BLOK XL',
		'CBL 11': 'CBL 11',
		'CBL 17': 'CBL 17',
