// This node can only generate code for data transformation based on provided input and schema.
// It cannot control or optimize the input from the code.
return $input.all();

// ============================================================
// n8n Code Node: Parse REFLEX / AMECO ORDER PDF -> Qargo orders
// Gebruik na "Extract from File"
// ============================================================

const items = $input.all();
const results = [];

// ------------------------------------------------------------
// Helpers
// ------------------------------------------------------------
function safeText(value) {
  return String(value || '')
    .replace(/\r/g, '\n')
    .replace(/\u00A0/g, ' ')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{2,}/g, '\n')
    .trim();
}

function cleanValue(value, fallback = '') {
  const v = String(value || '')
    .replace(/^[\s:._-]+/, '')
    .replace(/[\s:._-]+$/, '')
    .trim();

  return v || fallback;
}

function parseDecimalNumber(raw) {
  if (raw === undefined || raw === null) return null;

  const value = String(raw).trim();
  if (!value || value === '.' || value === '-') return null;

  const normalized = value
    .replace(/\./g, '')
    .replace(',', '.')
    .replace(/[^\d.-]/g, '');

  const num = Number(normalized);
  return Number.isFinite(num) ? num : null;
}

function parseIntNumber(raw) {
  const num = parseDecimalNumber(raw);
  return num === null ? null : Math.round(num);
}

function normalizeDateText(raw) {
  if (!raw) return '';

  let value = String(raw).trim();

  value = value.replace(/^([Oo])(?=\d[-/])/, '0');
  value = value
    .replace(/\bO(?=\d\b)/g, '0')
    .replace(/\bO(?=\d[-/])/g, '0');

  value = value.replace(/\s*\(.+?\)\s*$/g, '').trim();

  return value;
}

function toIsoDate(raw) {
  if (!raw) return null;

  const value = normalizeDateText(raw);
  if (!value || value === '.' || value === '-') return null;

  let m;

  // dd-mm-yyyy
  m = value.match(/^(\d{2})-(\d{2})-(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;

  // dd/mm/yyyy
  m = value.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;

  // yyyy-mm-dd
  m = value.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (m) return value;

  // dd-mm-yy
  m = value.match(/^(\d{2})-(\d{2})-(\d{2})$/);
  if (m) {
    const yy = Number(m[3]);
    const fullYear = yy >= 70 ? `19${m[3]}` : `20${m[3]}`;
    return `${fullYear}-${m[2]}-${m[1]}`;
  }

  // dd/mm/yy
  m = value.match(/^(\d{2})\/(\d{2})\/(\d{2})$/);
  if (m) {
    const yy = Number(m[3]);
    const fullYear = yy >= 70 ? `19${m[3]}` : `20${m[3]}`;
    return `${fullYear}-${m[2]}-${m[1]}`;
  }

  return null;
}

function extractFirstMatch(text, regex, groupIndex = 1) {
  const m = text.match(regex);
  return m?.[groupIndex]?.trim() || '';
}

function ensureName(name, fallback = 'Onbekend') {
  const value = String(name || '').trim();
  return value || fallback;
}

function getPossibleSubject(input) {
  return String(
    input.subject ||
    input.email_subject ||
    input.mail_subject ||
    input.message_subject ||
    input.originalSubject ||
    input.headers?.subject ||
    ''
  ).trim();
}

function mapTemperatureFromSubject(subject) {
  const s = String(subject || '').toLowerCase().replace(/\s+/g, ' ').trim();
  if (!s) return '';

  if (
    s.includes('ultra fresh') ||
    s.includes('ultrafresh') ||
    s.includes('0-2') ||
    s.includes('0 / 2') ||
    (s.includes('0°') && s.includes('2°'))
  ) {
    return 'Ultra Fresh (0°C / 3°C)';
  }

  if (
    s.includes('fresh') ||
    s.includes('4-7') ||
    s.includes('4 / 7') ||
    (s.includes('4°') && s.includes('7°'))
  ) {
    return 'Fresh (4°C / 7°C)';
  }

  if (
    s.includes('frozen') ||
    s.includes('-18') ||
    s.includes('-30')
  ) {
    return 'Frozen (-18°C / -30°C)';
  }

  if (
    s.includes('thermo') ||
    s.includes('8-20') ||
    s.includes('8 / 20')
  ) {
    return 'Thermo (8°C / 20°C)';
  }

  if (s.includes('ambient')) {
    return 'Ambient (Geen Temp)';
  }

  return '';
}

function countryFromText(value) {
  const v = String(value || '').trim().toLowerCase();

  if (!v) return '';
  if (v.includes('zweden') || v.includes('sweden') || v === 'se') return 'SE';
  if (v.includes('nederland') || v.includes('netherlands') || v === 'nl') return 'NL';
  if (v.includes('duitsland') || v.includes('germany') || v === 'de') return 'DE';
  if (v.includes('denemarken') || v.includes('denmark') || v === 'dk') return 'DK';
  if (v.includes('belgië') || v.includes('belgie') || v.includes('belgium') || v === 'be') return 'BE';
  return '';
}

function parsePostalCityLine(line, explicitCountry = '') {
  const value = String(line || '').trim();

  if (!value) {
    return {
      postal_code: '',
      city: '',
      country: explicitCountry || ''
    };
  }

  let m = value.match(/^([A-Z]-\d{4,6})\s+(.+)$/i);
  if (m) {
    const prefix = m[1].split('-')[0].toUpperCase();
    const inferredCountry =
      explicitCountry ||
      (prefix === 'D' ? 'DE' :
       prefix === 'B' ? 'BE' :
       prefix === 'DK' ? 'DK' :
       prefix === 'S' ? 'SE' : '');

    return {
      postal_code: m[1].trim().toUpperCase(),
      city: m[2].trim(),
      country: inferredCountry
    };
  }

  m = value.match(/^(\d{4}\s?[A-Z]{2})\s+(.+)$/i);
  if (m) {
    return {
      postal_code: m[1].trim().toUpperCase(),
      city: m[2].trim(),
      country: explicitCountry || 'NL'
    };
  }

  m = value.match(/^(\d{4,6})\s+(.+)$/);
  if (m) {
    return {
      postal_code: m[1].trim(),
      city: m[2].trim(),
      country: explicitCountry || ''
    };
  }

  return {
    postal_code: '',
    city: value,
    country: explicitCountry || ''
  };
}

function parseTopDeliveryBlock(lines) {
  const name = cleanValue(lines[0] || '');
  const address = cleanValue(lines[1] || '');
  const country = countryFromText(lines[3] || '');
  const postalCity = parsePostalCityLine(lines[2] || '', country);

  return {
    name: ensureName(name),
    address,
    postal_code: postalCity.postal_code || '',
    city: postalCity.city || '',
    country: postalCity.country || country || ''
  };
}

function parseAmecoFooter(text) {
  const footerMatch = text.match(
    /Kind regards,?\s*\n\s*(AMECO\s*BV)\s*\n\s*([^\n]+)\s*\n\s*([^\n]+)\s*(?:\n\s*([^\n]+))?/i
  );

  if (footerMatch) {
    const name = cleanValue(footerMatch[1], 'AMECO BV');
    const address = cleanValue(footerMatch[2]);
    const line3 = cleanValue(footerMatch[3]);
    const line4 = cleanValue(footerMatch[4]);
    const explicitCountry = countryFromText(line4) || 'NL';
    const postalCity = parsePostalCityLine(line3, explicitCountry);

    return {
      name,
      address,
      postal_code: postalCity.postal_code || '',
      city: postalCity.city || '',
      country: postalCity.country || explicitCountry || 'NL'
    };
  }

  return {
    name: 'AMECO BV',
    address: 'Ecofactorij 29',
    postal_code: '7325 WC',
    city: 'Apeldoorn',
    country: 'NL'
  };
}

function parseArticleLinesDutch(text) {
  const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
  const articles = [];

  for (const line of lines) {
    const m = line.match(/^(\d{3,})\s+(.+?)\s+(\d+[,.]\d+)\s*x\s+(\d+[,.]\d+)\s*=\s*(\d+[,.]\d+)$/i);
    if (m) {
      articles.push({
        article_number: cleanValue(m[1]),
        article_name: cleanValue(m[2]),
        colli: parseDecimalNumber(m[3]),
        portion_weight_kg: parseDecimalNumber(m[4]),
        total_weight_kg: parseDecimalNumber(m[5])
      });
    }
  }

  return articles;
}

function parseArticleLinesEnglish(text) {
  const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
  const articles = [];

  for (const line of lines) {
    const m = line.match(/^(\d{3,})\s+(.+?)\s+(\d+[,.]\d+)\s+x\s+(\d+[,.]\d+)\s+(\d+[,.]\d+)$/);
    if (m) {
      articles.push({
        article_number: cleanValue(m[1]),
        article_name: cleanValue(m[2]),
        colli: parseDecimalNumber(m[3]),
        portion_weight_kg: parseDecimalNumber(m[4]),
        total_weight_kg: parseDecimalNumber(m[5])
      });
    }
  }

  return articles;
}

function getInputText(input) {
  return safeText(
    input.text ||
    input.content ||
    input.raw_text ||
    input.extracted_text ||
    input.data ||
    input.body ||
    ''
  );
}

function detectDutchVariant(text) {
  const hasArticleHeader =
    /Art\.\s*Artikelnaam\s*stuks\s*x\s*portie\s*=\s*gewicht/i.test(text);

  const hasTotalColli =
    /Totaal\s+aantal\s+colli'?\(s\)/i.test(text);

  const hasTotalKg =
    /Totaal\s+kg'?s/i.test(text);

  const hasRoute =
    /ROUTENUMMER\s+\d+/i.test(text) ||
    /Routenummer\s*\.{0,}\s*:?\s*\d+/i.test(text);

  const hasKhNumber = /\bKH\d{6,}\b/i.test(text);
  const hasOrderNummer = /Order\s+nummer\s*\.{0,}\s*:?\s*/i.test(text);
  const hasLaaddatum = /Laaddatum\s*\.{0,}\s*:?\s*/i.test(text);
  const hasLeverdatum = /Leverdatum\s*\.{0,}\s*:?\s*/i.test(text);

  const score = [
    hasArticleHeader,
    hasTotalColli,
    hasTotalKg,
    hasRoute,
    hasKhNumber,
    hasOrderNummer,
    hasLaaddatum,
    hasLeverdatum
  ].filter(Boolean).length;

  return score >= 3;
}

function detectEnglishVariant(text, lines) {
  const firstLines = lines.slice(0, 20).join('\n');

  const hasOrderNumber =
    /Order\s*number\s*\.{0,}\s*:?\s*[^\n]+/i.test(text) ||
    /Order\s*No\.?\s*\.{0,}\s*:?\s*[^\n]+/i.test(text);

  const hasReference = /Reference\s*\.{0,}\s*:?\s*[^\n]+/i.test(text);
  const hasLoadingDay = /Loading\s*day\s*\.{0,}\s*:?\s*[^\n]*/i.test(text);
  const hasDeliveryDate = /Delivery\s*Date\s*\.{0,}\s*:?\s*[^\n]*/i.test(text);
  const hasConfirmText =
    /Hereby\s+we\s+confirm\s+your\s+order/i.test(text) ||
    /confirm\s+your\s+order/i.test(text);

  const hasAmeco = /AMECO/i.test(text);
  const hasRegards = /Kind\s+regards/i.test(text);

  const score = [
    hasOrderNumber,
    hasReference,
    hasLoadingDay,
    hasDeliveryDate,
    hasConfirmText,
    hasAmeco,
    hasRegards
  ].filter(Boolean).length;

  if (score >= 3 && (hasOrderNumber || hasConfirmText || hasAmeco)) return true;
  if (/AMECO/i.test(firstLines) && (hasOrderNumber || hasReference)) return true;

  return false;
}

function extractOrderNumber(text) {
  return (
    extractFirstMatch(text, /Order\s*nummer\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    extractFirstMatch(text, /Order\s*number\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    extractFirstMatch(text, /Order\s*No\.?\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    ''
  );
}

function extractReference(text) {
  return (
    extractFirstMatch(text, /Order\s+referentie\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    extractFirstMatch(text, /Reference\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    extractFirstMatch(text, /\b(KH\d{6,})\b/i) ||
    ''
  );
}

function extractPickupDateRaw(text) {
  return (
    extractFirstMatch(text, /Laaddatum\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    extractFirstMatch(text, /Loading\s*day\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    extractFirstMatch(text, /Order\s*date\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    ''
  );
}

function extractDeliveryDateRaw(text) {
  return (
    extractFirstMatch(text, /Leverdatum\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    extractFirstMatch(text, /Delivery\s*Date\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    ''
  );
}

function extractDeliveryTimeRaw(text) {
  return (
    extractFirstMatch(text, /Aanlevertijd\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    extractFirstMatch(text, /Delivery\s*Time\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    ''
  );
}

function extractLoadingAddressRaw(text) {
  return (
    extractFirstMatch(text, /Laadadres\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    extractFirstMatch(text, /Loading\s*address\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    ''
  );
}

function extractDeliveryBlock(lines) {
  const top = lines.slice(0, 8);

  if (top.length >= 4) {
    return parseTopDeliveryBlock([
      top[0] || '',
      top[1] || '',
      top[2] || '',
      top[3] || ''
    ]);
  }

  return {
    name: 'Onbekend',
    address: '',
    postal_code: '',
    city: '',
    country: ''
  };
}

// ------------------------------------------------------------
// Main loop
// ------------------------------------------------------------
for (const item of items) {
  const input = item.json || {};
  const text = getInputText(input);

  if (!text) continue;

  const lines = text.split('\n').map(l => l.trim()).filter(Boolean);

  const isDutchVariant = detectDutchVariant(text);
  const isEnglishVariant = detectEnglishVariant(text, lines);

  if (!isDutchVariant && !isEnglishVariant) {
    continue;
  }

  const deliveryBlock = extractDeliveryBlock(lines);
  const pickupBlock = parseAmecoFooter(text);

  const orderNumber = extractOrderNumber(text);
  const reference = extractReference(text);

  const pickupDateRaw = extractPickupDateRaw(text);
  const deliveryDateRaw = extractDeliveryDateRaw(text);
  const deliveryTimeRaw = extractDeliveryTimeRaw(text);
  const loadingAddressRaw = extractLoadingAddressRaw(text);

  const pickupDate = pickupDateRaw ? toIsoDate(pickupDateRaw) : null;
  const deliveryDate = deliveryDateRaw ? toIsoDate(deliveryDateRaw) : null;

  const transportBy = extractFirstMatch(text, /Transport\s*by\s*\.{0,}\s*:?\s*([^\n]+)/i);

  const palletQuantityRaw =
    extractFirstMatch(text, /Pallet\s*quantity\s*\.{0,}\s*:?\s*([^\n]+)/i) ||
    extractFirstMatch(text, /Aantal\s+palletplaatsen\s*\.{0,}\s*:?\s*([^\n]+)/i);

  const palletQuantity = parseIntNumber(palletQuantityRaw);

  const articlesDutch = parseArticleLinesDutch(text);
  const articlesEnglish = parseArticleLinesEnglish(text);
  const articles = articlesDutch.length ? articlesDutch : articlesEnglish;

  const totalMatchEnglish =
    text.match(/Total\s*:?\s*(\d+[,.]\d+)\s*[xX]\s*(\d+[,.]\d+)\s*KG/i) ||
    text.match(/Total\s*:?\s*(\d+[,.]\d+)\s*[xX]\s*(\d+[,.]\d+)\s*KGS?/i);

  const totalColliDutch =
    extractFirstMatch(text, /Totaal\s+aantal\s+colli'?\(s\)\.*\s*([0-9.,]+)/i) ||
    extractFirstMatch(text, /Totaal\s+aantal\s+colii'?\(s\)\.*\s*([0-9.,]+)/i);

  const totalKgDutch =
    extractFirstMatch(text, /Totaal\s+kg'?s\.*\s*([0-9.,]+)/i);

  const totalColli = totalMatchEnglish
    ? parseIntNumber(totalMatchEnglish[1])
    : parseIntNumber(totalColliDutch);

  const totalWeightKg = totalMatchEnglish
    ? parseDecimalNumber(totalMatchEnglish[2])
    : parseDecimalNumber(totalKgDutch);

  const articleDescriptions = articles
    .map(a => `${a.article_number} ${a.article_name}`.trim())
    .filter(Boolean);

  const mailSubject = getPossibleSubject(input);
  const mappedTemperature = mapTemperatureFromSubject(mailSubject);

  const routeNumber =
    extractFirstMatch(text, /ROUTENUMMER\s+([0-9]+)/i) ||
    extractFirstMatch(text, /Routenummer\s*\.{0,}\s*:?\s*([0-9]+)/i);

  const pickupNotes = [];
  if (pickupDate) pickupNotes.push(`Laaddatum: ${pickupDate}`);
  if (loadingAddressRaw) pickupNotes.push(`Laadadres: ${loadingAddressRaw}`);
  if (transportBy) pickupNotes.push(`Transport by: ${transportBy}`);
  if (routeNumber) pickupNotes.push(`Routenummer: ${routeNumber}`);

  const deliveryNotes = [];
  if (deliveryDate) deliveryNotes.push(`Leverdatum: ${deliveryDate}`);
  if (
    deliveryTimeRaw &&
    deliveryTimeRaw !== '.' &&
    deliveryTimeRaw !== '-' &&
    deliveryTimeRaw.toUpperCase() !== 'X'
  ) {
    deliveryNotes.push(`Aanlevertijd: ${deliveryTimeRaw}`);
  }
  if (mappedTemperature) {
    deliveryNotes.push(`Temperatuur: ${mappedTemperature}`);
  }

  const goodsCustomFields = {
    colli: totalColli || 0
  };

  if (mappedTemperature) {
    goodsCustomFields.temperature1 = mappedTemperature;
  }

  if (palletQuantity !== null) {
    goodsCustomFields.pallet_quantity = palletQuantity;
  }

  results.push({
    json: {
      transport_service: {
        name: 'Transport',
        code: '1'
      },
      transport_network: {
        name: 'Agro World'
      },
      service_level: {
        name: 'Next Day',
        code: 'AB'
      },
      customer_reference_number: reference || orderNumber || '',
      neutral_order_type: 'NO_NEUTRAL_ORDER',
      operation: 'CREATE',
      order_identifier: orderNumber || reference || '',
      customer: {
        name: pickupBlock.name || 'AMECO BV'
      },
      consignments: [
        {
          pickup_stop: {
            activity_label: 'PICKUP',
            note: pickupNotes.join(' | '),
            date: pickupDate,
            reference_number: reference || orderNumber || '',
            location: {
              address: pickupBlock.address || '',
              city: pickupBlock.city || '',
              country: pickupBlock.country || 'NL',
              postal_code: pickupBlock.postal_code || '',
              name: pickupBlock.name || 'AMECO BV'
            }
          },
          delivery_stop: {
            activity_label: 'DELIVERY',
            note: deliveryNotes.join(' | '),
            date: deliveryDate,
            reference_number: reference || orderNumber || '',
            location: {
              address: deliveryBlock.address || '',
              city: deliveryBlock.city || '',
              country: deliveryBlock.country || '',
              postal_code: deliveryBlock.postal_code || '',
              name: deliveryBlock.name || 'Onbekend'
            }
          },
          goods: [
            {
              quantity: 1,
              description: articleDescriptions.length
                ? articleDescriptions.join(' | ')
                : 'Onbekend artikel',
              total_weight_kg: totalWeightKg || 0,
              packaging_type: {
                name: 'EURO',
                packaging_size: {
                  name: 'EURO'
                }
              },
              custom_fields: {
                ...goodsCustomFields
              }
            }
          ]
        }
      ]
    },
    pairedItem: item.pairedItem
  });
}

if (!results.length) {
  const debugPreview = items.slice(0, 3).map((item, idx) => {
    const txt = getInputText(item.json || {});
    return {
      item: idx,
      keys: Object.keys(item.json || {}),
      preview: txt.slice(0, 1500)
    };
  });

  throw new Error(
    'Geen REFLEX / AMECO orderbevestigingen succesvol geparsed. Debug preview: ' +
    JSON.stringify(debugPreview)
  );
}

return results;

// ============================================================
// n8n Code Node: PDF laadlijst -> Qargo orders
//
// Regels:
// - Laad datum = pickup_stop.date
// - Losdatum = delivery_stop.date
// - Ieder ordernummer = aparte order
// - Laden = klant / opdrachtgever
// - Naam = leveradres naam
// - Colli / Pall / Box: eerste getal = colli, tweede = pallets
// - quantity = pallets, behalve als pallets = 0 dan quantity = colli
// - total_pallet_spaces = pallets
// - custom_fields.colli = colli
// - temperatuur 0-2 C = Ultra Fresh (0°C / 3°C)
// - packaging_type standaard = EURO
// - lege referentie = ordernummer
//
// Extra logica:
// - Als zelfde losadres + zelfde losdatum voorkomt
// - en er is precies één regel met pallets=0
//   en precies één regel met pallets>0
// - dan wordt de pallets=0 regel extra GOODS
//   onder dezelfde consignment van de pallets>0 order
//
// Extra:
// - geen null meesturen
// - null wordt op het einde automatisch ""
// ============================================================

const items = $input.all();
const parsedRows = [];
const output = [];

// ---------- HELPERS ----------
function cleanRepeatedWeekdays(str) {
  if (!str) return '';

  return String(str)
    .replace(/(Maandag)\1+/gi, 'Maandag')
    .replace(/(Dinsdag)\1+/gi, 'Dinsdag')
    .replace(/(Woensdag)\1+/gi, 'Woensdag')
    .replace(/(Donderdag)\1+/gi, 'Donderdag')
    .replace(/(Vrijdag)\1+/gi, 'Vrijdag')
    .replace(/(Zaterdag)\1+/gi, 'Zaterdag')
    .replace(/(Zondag)\1+/gi, 'Zondag');
}

function toIsoDate(raw) {
  if (!raw) return '';

  const cleaned = cleanRepeatedWeekdays(String(raw))
    .replace(/\s+/g, ' ')
    .trim();

  const match = cleaned.match(/(\d{2})\/(\d{2})\/(\d{4})/);
  if (!match) return '';

  return `${match[3]}-${match[2]}-${match[1]}`;
}

function detectCountry(postalCode, city) {
  const pc = String(postalCode || '').trim();
  const c = String(city || '').trim();

  if (/^\d{4}$/.test(pc)) return 'DK';
  if (/^\d{4}\s?[A-Z]{2}$/i.test(pc)) return 'NL';
  if (/^\d{5}$/.test(pc)) return 'DE';
  if (/rotterdam/i.test(c)) return 'NL';

  return '';
}

function cleanReference(reference, ordernr) {
  const value = String(reference || '')
    .replace(/\bTotaal\b.*$/i, '')
    .trim();

  if (!value) return ordernr;

  const stripped = value.replace(/\s+/g, '').toLowerCase();
  if (stripped === 'totaaltotaaltotaaltotaal') return ordernr;
  if (stripped === 'totaal') return ordernr;

  return value;
}

function mapTemperature(rawCondition) {
  const condition = String(rawCondition || '').toLowerCase().replace(/\s+/g, ' ').trim();

  if (
    condition.includes('0-2') ||
    condition.includes('0 / 2') ||
    (condition.includes('0') && condition.includes('2'))
  ) {
    return 'Ultra Fresh (0°C / 3°C)';
  }

  if (
    condition.includes('4-7') ||
    condition.includes('4 / 7')
  ) {
    return 'Fresh (4°C / 7°C)';
  }

  if (
    condition.includes('-18') ||
    condition.includes('-30') ||
    condition.includes('frozen')
  ) {
    return 'Frozen (-18°C / -30°C)';
  }

  if (
    condition.includes('8-20') ||
    condition.includes('8 / 20') ||
    condition.includes('thermo')
  ) {
    return 'Thermo (8°C / 20°C)';
  }

  return 'Ambient (Geen Temp)';
}

function mapDescription(rawCondition) {
  const temperature = mapTemperature(rawCondition).toLowerCase();

  if (temperature.includes('ultra fresh')) return 'Ultrafrisch';
  if (temperature.includes('fresh')) return 'Vers';
  if (temperature.includes('frozen')) return 'Frozen';
  if (temperature.includes('thermo')) return 'Thermo';

  return 'Ambient';
}

function mapPackagingType() {
  return 'EURO';
}

function splitNameAndAddress(prefixPart) {
  const value = String(prefixPart || '').trim();

  const match = value.match(/^(.*\S)\s+([A-Za-zÀ-ÿ0-9.\-\/ ]+\d+\w*)$/);

  if (match) {
    return {
      name: match[1].trim(),
      address: match[2].trim()
    };
  }

  return {
    name: value,
    address: ''
  };
}

function normalizeKeyPart(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

function replaceNullWithEmptyString(value) {
  if (value === null) return '';

  if (Array.isArray(value)) {
    return value.map(item => replaceNullWithEmptyString(item));
  }

  if (typeof value === 'object' && value !== null) {
    const out = {};
    for (const key of Object.keys(value)) {
      out[key] = replaceNullWithEmptyString(value[key]);
    }
    return out;
  }

  return value;
}

function buildGoods(row) {
  const safeQuantity = row.pallets > 0 ? row.pallets : row.colli;

  return {
    quantity: safeQuantity,
    total_pallet_spaces: row.pallets,
    description: mapDescription(row.condition),
    total_weight_kg: '',
    packaging_type: {
      name: row.packagingType,
      packaging_size: {
        name: row.packagingType
      }
    },
    custom_fields: {
      temperature1: mapTemperature(row.condition),
      colli: row.colli,
      reference_number: row.orderNumber
    }
  };
}

function buildConsignment(row, pickupContext, goodsOverride = null) {
  return {
    pickup_stop: {
      activity_label: 'PICKUP',
      note: '',
      date: pickupContext.pickupDate,
      reference_number: row.orderNumber,
      location: {
        address: '',
        city: pickupContext.pickupCity,
        country: pickupContext.pickupCountry,
        postal_code: pickupContext.pickupPostalCode,
        name: pickupContext.pickupName
      }
    },
    delivery_stop: {
      activity_label: 'DELIVERY',
      note: `Temperatuur: ${mapTemperature(row.condition)}`,
      date: row.deliveryDate,
      reference_number: row.referenceNumber,
      location: {
        address: row.deliveryAddress,
        city: row.deliveryCity,
        country: row.deliveryCountry,
        postal_code: row.deliveryPostalCode,
        name: row.deliveryName
      }
    },
    goods: goodsOverride || [buildGoods(row)]
  };
}

function buildOrder(row, pickupContext, consignments, pairedItem) {
  return {
    json: {
      transport_service: {
        name: 'Transport',
        code: '1'
      },
      transport_network: {
        name: 'Agro World'
      },
      customer_reference_number: row.referenceNumber,
      neutral_order_type: 'NO_NEUTRAL_ORDER',
      operation: 'CREATE',
      order_identifier: row.orderNumber,
      customer: {
        name: pickupContext.pickupName
      },
      consignments
    },
    pairedItem
  };
}

// ---------- LOOP OVER ALLE PDF ITEMS ----------
for (const item of items) {
  const input = item.json || {};

  const rawText =
    input.text ||
    input.content ||
    input.raw_text ||
    input.extracted_text ||
    JSON.stringify(input);

  if (!rawText || String(rawText).trim() === '') {
    continue;
  }

  let text = String(rawText)
    .replace(/\r/g, '\n')
    .replace(/\u00A0/g, ' ')
    .replace(/[ \t]+/g, ' ')
    .replace(/TotaalTotaalTotaalTotaal/g, ' Totaal ')
    .replace(/\n\s*\*\*\s*\n/g, '\n')
    .replace(/\n{2,}/g, '\n')
    .trim();

  text = text.replace(
    /(Laden\s*:\s*[^,\n]+,\s*[0-9]{4}\s?[A-Z]{2}\s*,\s*[^,\n]+)(?:\1)+/gi,
    '$1'
  );

  const pickupDateMatch = text.match(/Laad datum\s*:.*?(\d{2}\/\d{2}\/\d{4})/i);
  const pickupDate = pickupDateMatch ? toIsoDate(pickupDateMatch[1]) : '';

  const pickupMatch = text.match(
    /Laden\s*:\s*([^,]+),\s*([0-9]{4}\s?[A-Z]{2}|[0-9]{5})\s*,\s*([^,\n]+?)(?=Laden\s*:|\n|$)/i
  );

  const pickupName = pickupMatch?.[1]?.trim() || '';
  const pickupPostalCode = pickupMatch?.[2]?.trim() || '';
  const pickupCity = pickupMatch?.[3]?.trim() || '';
  const pickupCountry = detectCountry(pickupPostalCode, pickupCity) || 'NL';

  const pickupContext = {
    pickupDate,
    pickupName,
    pickupPostalCode,
    pickupCity,
    pickupCountry
  };

  const rawLines = text
    .split('\n')
    .map(v => v.trim())
    .filter(Boolean);

  const orderLines = [];
  let currentLine = null;

  for (const line of rawLines) {
    if (/^\d{6,}\s/.test(line)) {
      if (currentLine) {
        orderLines.push(currentLine.trim());
      }
      currentLine = line;
      continue;
    }

    if (!currentLine) continue;

    if (/^items niet verdelen over pall/i.test(line)) {
      continue;
    }

    if (/^Totaal\b/i.test(line)) {
      if (currentLine) {
        orderLines.push(currentLine.trim());
        currentLine = null;
      }
      continue;
    }

    if (
      /^Laadopdracht\b/i.test(line) ||
      /^Ordnr\b/i.test(line) ||
      /^Naam\b/i.test(line) ||
      /^Laden\s*:/i.test(line) ||
      /^- Geplande aantallen/i.test(line) ||
      /^Verzonden\b/i.test(line) ||
      /^Goedegebuur\b/i.test(line) ||
      /^~subject:/i.test(line)
    ) {
      continue;
    }

    currentLine += ' ' + line;
  }

  if (currentLine) {
    orderLines.push(currentLine.trim());
  }

  for (const line of orderLines) {
    const cleanedLine = line
      .replace(/\*+/g, ' ')
      .replace(/\s{2,}/g, ' ')
      .trim();

    const orderNumberMatch = cleanedLine.match(/^(\d{6,})\s+/);
    if (!orderNumberMatch) continue;

    const orderNumber = orderNumberMatch[1];

    const endMatch = cleanedLine.match(
      /(Maandag|Dinsdag|Woensdag|Donderdag|Vrijdag|Zaterdag|Zondag)\s+(\d{2}\/\d{2}\/\d{4})\s+(.+)$/i
    );
    if (!endMatch) continue;

    const deliveryDate = toIsoDate(endMatch[2]);
    const referenceNumber = cleanReference(endMatch[3], orderNumber);

    const beforeEnd = cleanedLine.slice(0, endMatch.index).trim();

    const quantityMatch = beforeEnd.match(/(\d+)\s*\/\s*(\d+)(?:\s*\/\s*(\d+))?$/);
    if (!quantityMatch) continue;

    const colli = Number(quantityMatch[1] || 0);
    const pallets = Number(quantityMatch[2] || 0);

    let beforeQuantity = beforeEnd.slice(0, quantityMatch.index).trim();

    const conditionMatch = beforeQuantity.match(
      /(Vers\s*0-2\s*C|Vers\s*4-7\s*C|Fresh.*?|Ultra Fresh.*?|Frozen.*?|Ambient.*?|Thermo.*?)$/i
    );
    if (!conditionMatch) continue;

    const condition = conditionMatch[1].trim();
    const destinationPart = beforeQuantity
      .slice(0, conditionMatch.index)
      .replace(new RegExp(`^${orderNumber}\\s+`), '')
      .trim();

    const postalCityMatch = destinationPart.match(/(\d{4,5}(?:\s?[A-Z]{2})?)\s+(.+)$/);
    if (!postalCityMatch) continue;

    const deliveryPostalCode = postalCityMatch[1].trim();
    const deliveryCity = postalCityMatch[2].trim();
    const beforePostalCity = destinationPart.slice(0, postalCityMatch.index).trim();

    const split = splitNameAndAddress(beforePostalCity);
    const deliveryName = split.name;
    const deliveryAddress = split.address;
    const deliveryCountry = detectCountry(deliveryPostalCode, deliveryCity);
    const packagingType = mapPackagingType();

    parsedRows.push({
      orderNumber,
      referenceNumber,
      deliveryDate,
      colli,
      pallets,
      condition,
      deliveryPostalCode,
      deliveryCity,
      deliveryAddress,
      deliveryName,
      deliveryCountry,
      packagingType,
      pickupContext,
      pairedItem: item.pairedItem
    });
  }
}

if (!parsedRows.length) {
  throw new Error('Wel ordernummers gevonden, maar parsing van de orderregels mislukt');
}

// ---------- GROEPEREN OP LOSADRES + LOSDATUM ----------
const groups = new Map();

for (const row of parsedRows) {
  const key = [
    normalizeKeyPart(row.deliveryName),
    normalizeKeyPart(row.deliveryAddress),
    normalizeKeyPart(row.deliveryPostalCode),
    normalizeKeyPart(row.deliveryCity),
    normalizeKeyPart(row.deliveryDate)
  ].join('|');

  if (!groups.has(key)) {
    groups.set(key, []);
  }
  groups.get(key).push(row);
}

// ---------- SAMENVOEGLOGICA ----------
const handledOrderNumbers = new Set();

for (const rows of groups.values()) {
  const zeroRows = rows.filter(r => r.pallets === 0);
  const palletRows = rows.filter(r => r.pallets > 0);

  if (zeroRows.length === 1 && palletRows.length === 1) {
    const zeroRow = zeroRows[0];
    const palletRow = palletRows[0];

    const mergedGoods = [
      buildGoods(palletRow),
      buildGoods(zeroRow)
    ];

    output.push(
      buildOrder(
        palletRow,
        palletRow.pickupContext,
        [
          buildConsignment(
            palletRow,
            palletRow.pickupContext,
            mergedGoods
          )
        ],
        palletRow.pairedItem
      )
    );

    handledOrderNumbers.add(zeroRow.orderNumber);
    handledOrderNumbers.add(palletRow.orderNumber);
  }
}

// ---------- REST NORMAAL ALS LOSSE ORDER ----------
for (const row of parsedRows) {
  if (handledOrderNumbers.has(row.orderNumber)) continue;

  output.push(
    buildOrder(
      row,
      row.pickupContext,
      [buildConsignment(row, row.pickupContext)],
      row.pairedItem
    )
  );
}

return output.map(item => ({
  ...item,
  json: replaceNullWithEmptyString(item.json)
}));

// ============================================================
// n8n Code Node: Parse THERMOTRAFFIC PDF -> Qargo orders
// Gebruik na "Extract from File"
// Werkt ook als meerdere PDF-items tegelijk binnenkomen
// Specifiek afgestemd op Thermotraffic Crystal Reports PDF
//
// Belangrijke logica:
// - Jumbopallet wordt behandeld als BLOKPALLET
// - Industrial pallet / industriepallet wordt behandeld als BLOKPALLET
// - Lege palletwaarde wordt niet als 1 pallet doorgestuurd
// - "2 Jumbopallets gestapeld op 1 blokpalletplaats"
//   => quantity = 2, packaging_type = BLOK, total_pallet_spaces = 1
// ============================================================

const items = $input.all();
const results = [];

// ------------------------------------------------------------
// Helpers
// ------------------------------------------------------------
function safeText(value) {
  return String(value || '')
    .replace(/\r/g, '\n')
    .replace(/\u00A0/g, ' ')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{2,}/g, '\n')
    .trim();
}

function normalizeInline(value) {
  return String(value || '')
    .replace(/\s+/g, ' ')
    .trim();
}

function cleanValue(value, fallback = '') {
  const v = normalizeInline(value)
    .replace(/^[\s:.-]+/, '')
    .replace(/[\s:.-]+$/, '')
    .trim();

  return v || fallback;
}

function normalizeCompanyName(value, fallback = '') {
  const v = cleanValue(value, fallback);
  if (!v) return fallback || '';
  if (/^thermotraffic\s+b\.?v\.?$/i.test(v)) return 'Thermotraffic B.V.';
  return v;
}

function toIsoDate(raw) {
  if (!raw) return null;

  const value = normalizeInline(raw)
    .replace(/[Oo](?=\d)/g, '0');

  let m = value.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;

  m = value.match(/^(\d{2})-(\d{2})-(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;

  return null;
}

function parseDecimalNumber(raw) {
  if (raw === undefined || raw === null) return null;
  const match = String(raw).replace(/\s/g, '').match(/-?\d+(?:[.,]\d+)?/);
  if (!match) return null;
  const num = Number(match[0].replace(',', '.'));
  return Number.isFinite(num) ? num : null;
}

function parseIntNumber(raw) {
  const n = parseDecimalNumber(raw);
  return n === null ? null : Math.round(n);
}

function parsePostalCityLine(line) {
  const value = normalizeInline(line);

  let m = value.match(/^(\d{4}\s?[A-Z]{2})\s+(.+)$/i);
  if (m) {
    return {
      postal_code: m[1].trim().toUpperCase(),
      city: m[2].trim(),
      country: 'NL'
    };
  }

  m = value.match(/^([A-Z]-\d{4,6})\s+(.+)$/i);
  if (m) {
    const prefix = m[1].split('-')[0].toUpperCase();
    const country =
      prefix === 'D' ? 'DE' :
      prefix === 'B' ? 'BE' :
      prefix === 'DK' ? 'DK' :
      prefix === 'S' ? 'SE' : '';

    return {
      postal_code: m[1].trim().toUpperCase(),
      city: m[2].trim(),
      country
    };
  }

  m = value.match(/^(\d{4,6})\s+(.+)$/);
  if (m) {
    return {
      postal_code: m[1].trim(),
      city: m[2].trim(),
      country: ''
    };
  }

  return {
    postal_code: '',
    city: '',
    country: ''
  };
}

function mapTemperature(raw) {
  const s = normalizeInline(raw).toLowerCase();

  if (!s) return '';

  if (
    s.includes('frozen') ||
    s.includes('below zero') ||
    /minus\s*\d+/.test(s) ||
    /-\s*\d+\s*(°c|c|degrees?|celcius|celsius)?/.test(s) ||
    /min\.*\s*-\s*\d+/.test(s)
  ) {
    return 'Frozen (-18°C / -30°C)';
  }

  if (
    s.includes('0-2') ||
    s.includes('0 / 2') ||
    s.includes('0 to 2')
  ) {
    return 'Ultra Fresh (0°C / 3°C)';
  }

  if (
    s.includes('4-7') ||
    s.includes('4 / 7') ||
    s.includes('4 to 7') ||
    s === 'fresh'
  ) {
    return 'Fresh (4°C / 7°C)';
  }

  if (
    s.includes('8-20') ||
    s.includes('8 / 20') ||
    s.includes('8 to 20') ||
    s.includes('thermo')
  ) {
    return 'Thermo (8°C / 20°C)';
  }

  if (
    s.includes('ambient') ||
    s.includes('geen temp') ||
    s.includes('room temperature')
  ) {
    return 'Ambient (Geen Temp)';
  }

  return normalizeInline(raw);
}

function isThermotrafficDocument(input, text) {
  const infoCreator = String(input.info?.Creator || '').toLowerCase();
  const infoProducer = String(input.info?.Producer || '').toLowerCase();
  const fullText = String(text || '').toLowerCase();

  return (
    infoCreator.includes('crystal reports') ||
    infoProducer.includes('powered by crystal') ||
    fullText.includes('thermotraffic b.v.') ||
    fullText.includes('thermotraffic b.v') ||
    fullText.includes('transportopdracht / laadinstructies')
  );
}

function lines(text) {
  return safeText(text)
    .split('\n')
    .map(normalizeInline)
    .filter(Boolean);
}

function findNextMeaningfulLines(arr, startIndex, count = 8) {
  const out = [];
  for (let i = startIndex; i < arr.length && out.length < count; i++) {
    const v = arr[i];
    if (!v) continue;
    if (/^:+$/.test(v)) continue;
    out.push(v);
  }
  return out;
}

function extractDateAndTime(line) {
  const value = normalizeInline(line);

  const m = value.match(/(\d{2}[\/-]\d{2}[\/-]\d{4})(?:\s*\/\s*(.*?))?(?:Losdatum\/Tijd|Laaddag\/Tijd)?$/i);
  if (!m) {
    return {
      date: null,
      time_note: ''
    };
  }

  return {
    date: toIsoDate(m[1]),
    time_note: cleanValue(m[2] || '')
  };
}

// ------------------------------------------------------------
// Extractors
// ------------------------------------------------------------
function extractOrderNumber(text) {
  const m = text.match(/Ons referentie nr\.?\s*:?\s*([^\n]+)/i);
  if (!m) return '';
  return cleanValue(m[1].replace(/\(op\s+uw\s+fact\.\s+vermelden\)\s*:?/i, ''));
}

function extractPickup(text) {
  const arr = lines(text);

  const idxLaadplaats = arr.findIndex(v => /^Laadplaats$/i.test(v));
  const idxLaadref = arr.findIndex(v => /^Laadreferentie$/i.test(v));

  if (idxLaadplaats === -1) {
    return {
      name: 'Thermotraffic B.V.',
      address: '',
      postal_code: '',
      city: '',
      country: '',
      date: null,
      time_note: '',
      reference: ''
    };
  }

  const endIndex = idxLaadref !== -1 ? idxLaadref + 6 : Math.min(idxLaadplaats + 12, arr.length);
  const block = arr.slice(idxLaadplaats, endIndex);

  const dateLine = block.find(v => /\d{2}[\/-]\d{2}[\/-]\d{4}/.test(v)) || '';
  const postalLine = block.find(v => /^(\d{4}\s?[A-Z]{2}|[A-Z]-\d{4,6}|\d{4,6})\s+/.test(v)) || '';

  const dateIndex = block.findIndex(v => v === dateLine);
  const postalIndex = block.findIndex(v => v === postalLine);

  const beforeDate = dateIndex >= 0
    ? block.slice(0, dateIndex).filter(v =>
        !/^Laadplaats$/i.test(v) &&
        !/^Laaddag\/Tijd$/i.test(v) &&
        !/^:+$/.test(v)
      )
    : [];

  const name = normalizeCompanyName(beforeDate[0] || 'Thermotraffic B.V.', 'Thermotraffic B.V.');
  const address = cleanValue(beforeDate[1] || '');

  let ref = '';
  if (postalIndex >= 0) {
    for (let i = postalIndex + 1; i < Math.min(postalIndex + 4, block.length); i++) {
      if (block[i] && !/^Laadreferentie$/i.test(block[i]) && !/^:+$/.test(block[i])) {
        ref = cleanValue(block[i]);
        break;
      }
    }
  }

  const postal = parsePostalCityLine(postalLine);
  const dt = extractDateAndTime(dateLine);

  return {
    name,
    address,
    postal_code: postal.postal_code,
    city: postal.city,
    country: postal.country,
    date: dt.date,
    time_note: dt.time_note,
    reference: ref
  };
}

function extractDelivery(text) {
  const arr = lines(text);

  const idxDouane = arr.findIndex(v => /^Douanestatus$/i.test(v));
  const idxLosadres = arr.findIndex(v => /^Losadres$/i.test(v));
  const idxLosRef = arr.findIndex(v => /^Losreferentie$/i.test(v));

  if (idxDouane !== -1) {
    const name = arr[idxDouane + 1] || '';
    const address = arr[idxDouane + 2] || '';
    const dateRawLine = arr[idxDouane + 3] || '';

    let postalLine = '';
    let referenceLine = '';

    if (idxLosadres !== -1) {
      postalLine = arr[idxLosadres + 1] || '';
      referenceLine = arr[idxLosadres + 2] || '';
    } else {
      const nearby = arr.slice(idxDouane, Math.min(idxDouane + 12, arr.length));
      postalLine = nearby.find(v => /^(\d{4}\s?[A-Z]{2}|[A-Z]-\d{4,6}|\d{4,6})\s+/.test(v)) || '';
    }

    const dt = extractDateAndTime(dateRawLine);
    const postal = parsePostalCityLine(postalLine);

    return {
      name: normalizeCompanyName(name, 'Onbekend losadres'),
      address: cleanValue(address),
      postal_code: postal.postal_code,
      city: postal.city,
      country: postal.country,
      date: dt.date,
      time_note: dt.time_note,
      reference: cleanValue(referenceLine || '')
    };
  }

  if (idxLosadres !== -1) {
    const before = arr.slice(Math.max(0, idxLosadres - 8), idxLosadres);
    const after = arr.slice(idxLosadres, Math.min(idxLosadres + 8, arr.length));

    const postalLine = after.find(v => /^(\d{4}\s?[A-Z]{2}|[A-Z]-\d{4,6}|\d{4,6})\s+/.test(v)) || '';
    const postal = parsePostalCityLine(postalLine);

    const dateLine = before.find(v => /\d{2}[\/-]\d{2}[\/-]\d{4}/.test(v)) || '';
    const dt = extractDateAndTime(dateLine);

    const possibleName = before.find(v =>
      !/^:+$/.test(v) &&
      !/Losdatum\/Tijd/i.test(v) &&
      !/\d{2}[\/-]\d{2}[\/-]\d{4}/.test(v) &&
      !/^Douanestatus$/i.test(v)
    ) || '';

    const possibleAddressCandidates = before.filter(v =>
      !/^:+$/.test(v) &&
      !/Losdatum\/Tijd/i.test(v) &&
      !/\d{2}[\/-]\d{2}[\/-]\d{4}/.test(v) &&
      !/^Douanestatus$/i.test(v)
    );

    const address = possibleAddressCandidates.length > 1 ? possibleAddressCandidates[1] : '';

    let reference = '';
    if (idxLosRef !== -1) {
      const next = findNextMeaningfulLines(arr, idxLosRef + 1, 3);
      reference = cleanValue(next[0] || '');
    }

    return {
      name: normalizeCompanyName(possibleName, 'Onbekend losadres'),
      address: cleanValue(address),
      postal_code: postal.postal_code,
      city: postal.city,
      country: postal.country,
      date: dt.date,
      time_note: dt.time_note,
      reference
    };
  }

  return {
    name: 'Onbekend losadres',
    address: '',
    postal_code: '',
    city: '',
    country: '',
    date: null,
    time_note: '',
    reference: ''
  };
}

function extractColli(text) {
  const arr = lines(text);
  const idx = arr.findIndex(v => /^Colli aantal$/i.test(v) || /^Colli aantal\s*:/i.test(v));
  if (idx === -1) return '';

  const sameLine = arr[idx].replace(/^Colli aantal\s*:?\s*/i, '').trim();
  if (sameLine) return sameLine;

  for (let i = idx + 1; i < Math.min(idx + 5, arr.length); i++) {
    if (arr[i]) return arr[i];
  }

  return '';
}

function extractWeight(text) {
  const arr = lines(text);
  const idx = arr.findIndex(v => /^Gewicht:?$/i.test(v) || /^Gewicht\s*:/i.test(v));
  if (idx === -1) return '';

  const sameLine = arr[idx].replace(/^Gewicht\s*:?\s*/i, '').trim();
  if (sameLine) return sameLine;

  for (let i = idx + 1; i < Math.min(idx + 5, arr.length); i++) {
    if (arr[i]) return arr[i];
  }

  return '';
}

function extractPallets(text) {
  const arr = lines(text);

  const idx = arr.findIndex(v => /^Pallet aantal\/soort/i.test(v));
  if (idx !== -1) {
    const line = arr[idx];

    let sameLine = line.replace(/^Pallet aantal\/soort\s*:?\s*/i, '').trim();

    if (sameLine) {
      sameLine = sameLine.split(/Ruilen\s*:/i)[0].trim();
      if (sameLine && !/^nee$/i.test(sameLine)) {
        return sameLine;
      }
    }

    for (let i = idx + 1; i < Math.min(idx + 8, arr.length); i++) {
      const v = arr[i];
      if (!v) continue;
      if (/^nee$/i.test(v)) continue;

      if (/jumbo|europallet|blokpallet|blok pallet|industrial|industrie|pallet|chep|h1|6549/i.test(v)) {
        return v;
      }
    }
  }

  const fallback = text.match(/Pallet aantal\/soort\s*:\s*([^\n]+)/i);
  if (fallback) {
    let value = cleanValue(fallback[1]);
    value = value.split(/Ruilen\s*:/i)[0].trim();

    if (value && !/^nee$/i.test(value)) {
      return value;
    }
  }

  return '';
}

function extractCargo(text) {
  const arr = lines(text);
  const idx = arr.findIndex(v => /^Lading\s*:?\s*$/i.test(v) || /^Lading\s*:/i.test(v));
  if (idx === -1) return '';

  const sameLine = arr[idx].replace(/^Lading\s*:?\s*/i, '').trim();
  if (sameLine) return cleanValue(sameLine);

  for (let i = idx + 1; i < Math.min(idx + 4, arr.length); i++) {
    const v = arr[i];
    if (
      v &&
      !/^Transporttemperatuur$/i.test(v) &&
      !/^:+$/.test(v)
    ) {
      return cleanValue(v);
    }
  }

  return '';
}

function extractTransportTemp(text) {
  const arr = lines(text);
  const idx = arr.findIndex(v => /^Transporttemperatuur$/i.test(v) || /^Transporttemperatuur\s*:/i.test(v));
  if (idx === -1) return '';

  const sameLine = arr[idx].replace(/^Transporttemperatuur\s*:?\s*/i, '').trim();
  if (sameLine) return cleanValue(sameLine);

  for (let i = idx + 1; i < Math.min(idx + 4, arr.length); i++) {
    const v = arr[i];
    if (v && !/^:+$/.test(v)) return cleanValue(v);
  }

  return '';
}

// ------------------------------------------------------------
// Pallet parsing
// Jumbo pallet = BLOK pallet
// Industrial pallet = BLOK pallet
// ------------------------------------------------------------
function parsePalletInfo(raw, fullText = '') {
  const s = normalizeInline(raw).toLowerCase();
  const text = normalizeInline(fullText).toLowerCase();

  if (!s) {
    return {
      quantity: null,
      packagingType: null,
      totalPalletSpaces: null
    };
  }

  // Specifieke code
  if (s.includes('6549')) {
    return {
      quantity: 2,
      packagingType: 'BLOK',
      totalPalletSpaces: 2
    };
  }

  // Jumbo pallet = BLOK
  let m = s.match(/(\d+)\s*jumbo\s*pallets?/i) || s.match(/(\d+)\s*jumbopallets?/i);
  if (m) {
    const qty = parseInt(m[1], 10);

    const stackedOnOneBlockPalletSpace =
      /gestapeld op 1 blokpalletplaats/i.test(text) ||
      /gestapeld op 1 blok palletplaats/i.test(text) ||
      /2 jumbo pallets gestapeld op 1 blokpalletplaats/i.test(text);

    return {
      quantity: qty,
      packagingType: 'BLOK',
      totalPalletSpaces: stackedOnOneBlockPalletSpace ? 1 : qty
    };
  }

  // Blok pallet = BLOK
  m =
    s.match(/(\d+)\s*blok\s*pallets?/i) ||
    s.match(/(\d+)\s*blokpallets?/i);
  if (m) {
    const qty = parseInt(m[1], 10);
    return {
      quantity: qty,
      packagingType: 'BLOK',
      totalPalletSpaces: qty
    };
  }

  // Industrial / industrie pallet = BLOK
  m =
    s.match(/(\d+)\s*industrial\s*pallets?/i) ||
    s.match(/(\d+)\s*industrie\s*pallets?/i) ||
    s.match(/(\d+)\s*industriepallets?/i) ||
    s.match(/(\d+)\s*industriepallets?/i);
  if (m) {
    const qty = parseInt(m[1], 10);
    return {
      quantity: qty,
      packagingType: 'BLOK',
      totalPalletSpaces: qty
    };
  }

  m = s.match(/(\d+)\s*europallets?/i) || s.match(/(\d+)\s*euro\s*pallets?/i);
  if (m) {
    const qty = parseInt(m[1], 10);
    return {
      quantity: qty,
      packagingType: 'EURO',
      totalPalletSpaces: qty
    };
  }

  m = s.match(/(\d+)\s*chep/i);
  if (m) {
    const qty = parseInt(m[1], 10);
    return {
      quantity: qty,
      packagingType: 'CHEP',
      totalPalletSpaces: qty
    };
  }

  m = s.match(/(\d+)\s*h1/i);
  if (m) {
    const qty = parseInt(m[1], 10);
    return {
      quantity: qty,
      packagingType: 'H1',
      totalPalletSpaces: qty
    };
  }

  m = s.match(/(\d+)\s*pallets?/i);
  if (m) {
    const qty = parseInt(m[1], 10);
    return {
      quantity: qty,
      packagingType: 'EURO',
      totalPalletSpaces: qty
    };
  }

  return {
    quantity: null,
    packagingType: null,
    totalPalletSpaces: null
  };
}

// ------------------------------------------------------------
// Main
// ------------------------------------------------------------
for (const item of items) {
  const input = item.json || {};
  const rawText =
    input.text ||
    input.content ||
    input.raw_text ||
    input.extracted_text ||
    '';

  const text = safeText(rawText);

  if (!text) continue;
  if (!isThermotrafficDocument(input, text)) continue;

  const orderNumber = extractOrderNumber(text);
  const pickup = extractPickup(text);
  const delivery = extractDelivery(text);

  const colliRaw = extractColli(text);
  const weightRaw = extractWeight(text);
  const palletRaw = extractPallets(text);
  const cargoRaw = extractCargo(text);
  const transportTempRaw = extractTransportTemp(text);

  const colliCount = parseIntNumber(colliRaw) || 0;
  const totalWeightKg = parseDecimalNumber(weightRaw) || 0;
  const palletInfo = parsePalletInfo(palletRaw, text);
  const mappedTemperature = mapTemperature(transportTempRaw);

  const pickupNotes = [];
  const deliveryNotes = [];

  if (pickup.time_note) pickupNotes.push(`Laadtijd: ${pickup.time_note}`);
  if (delivery.time_note) deliveryNotes.push(`Lostijd: ${delivery.time_note}`);
  if (mappedTemperature) deliveryNotes.push(`Temperatuur: ${mappedTemperature}`);

  const goodsCustomFields = {
    colli: colliCount
  };

  if (mappedTemperature) {
    goodsCustomFields.temperature1 = mappedTemperature;
  }

  const goods = {
    total_weight_kg: totalWeightKg,
    description: cargoRaw || '',
    custom_fields: goodsCustomFields
  };

  if (palletInfo.quantity !== null) {
    goods.quantity = palletInfo.quantity;
  }

  if (palletInfo.packagingType) {
    goods.packaging_type = {
      name: palletInfo.packagingType
    };
  }

  if (palletInfo.totalPalletSpaces !== null) {
    goods.total_pallet_spaces = palletInfo.totalPalletSpaces;
  }

  results.push({
    json: {
      transport_service: {
        name: 'Transport',
        code: '1'
      },
      transport_network: {
        name: 'Agro World'
      },
      customer_reference_number: orderNumber,
      neutral_order_type: 'NO_NEUTRAL_ORDER',
      operation: 'CREATE',
      order_identifier: orderNumber,
      customer: {
        name: 'Thermotraffic B.V.'
      },
      consignments: [
        {
          pickup_stop: {
            activity_label: 'PICKUP',
            note: pickupNotes.join(' | '),
            date: pickup.date,
            reference_number: pickup.reference || orderNumber,
            location: {
              address: pickup.address || '',
              city: pickup.city || '',
              country: pickup.country || '',
              postal_code: pickup.postal_code || '',
              name: pickup.name || 'Thermotraffic B.V.'
            }
          },
          delivery_stop: {
            activity_label: 'DELIVERY',
            note: deliveryNotes.join(' | '),
            date: delivery.date,
            reference_number: delivery.reference || orderNumber,
            location: {
              address: delivery.address || '',
              city: delivery.city || '',
              country: delivery.country || '',
              postal_code: delivery.postal_code || '',
              name: delivery.name || 'Onbekend losadres'
            }
          },
          goods: [goods]
        }
      ]
    },
    pairedItem: item.pairedItem
  });
}

if (!results.length) {
  throw new Error('Geen Thermotraffic PDF succesvol geparsed');
}

return results;

