return $input.all();

// ============================================================
// n8n Code Node: Parse WETRALOG PDF -> Qargo orders
// Direct na "Extract from File"
//
// Doel:
// - 1 laadadres + meerdere referentieregels correct verwerken
// - koppelen op pickup reference <-> delivery reference
// - per gekoppelde reference een aparte order maken
//
// Werkt op actuele WETRALOG layout zoals:
// 1 WFL Werk Coesfeld Stockum 2 D 48653 Coesfeld
// 07.04.2026 15:00 - 15:00 .
// 81565124 H1EUROPAL 12 12,00 SP 4.643,20 kg Frisch 0°C
// 81565147 WTLDOLAVHB 3 3,75 SP 1.610,10 kg Frisch 0°C
//
// + delivery:
// 1 Hilton Foods DK A/S Brunagervej 2-4 DK 8361 Aarhus
// 08.04.2026 08:00 - 08:00
// 81565124 Entladeeinheiten: 12 12,00 SP 4.643,20 kg
// ============================================================

const items = $input.all();
const results = [];

// ------------------------------------------------------------
// Helpers
// ------------------------------------------------------------
function safeText(value) {
  return String(value || '')
    .replace(/\r/g, '\n')
    .replace(/\u00A0/g, ' ')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{2,}/g, '\n')
    .trim();
}

function normalizeInline(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function ensureName(name, fallback = 'Onbekend') {
  const value = normalizeInline(name);
  return value || fallback;
}

function extractFirstMatch(text, regex, groupIndex = 1) {
  const m = String(text || '').match(regex);
  return m?.[groupIndex]?.trim() || '';
}

function toIsoDate(raw) {
  if (!raw) return null;
  const value = String(raw).trim();

  let m = value.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;

  m = value.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;

  m = value.match(/^(\d{2})-(\d{2})-(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;

  return null;
}

function parseDecimalNumber(raw) {
  if (raw === undefined || raw === null) return null;

  const value = String(raw).trim();
  if (!value) return null;

  const cleaned = value
    .replace(/\s/g, '')
    .replace(/\.(?=\d{3}\b)/g, '')
    .replace(',', '.');

  const match = cleaned.match(/-?\d+(?:\.\d+)?/);
  if (!match) return null;

  const num = Number(match[0]);
  return Number.isFinite(num) ? num : null;
}

function parseIntNumber(raw) {
  const num = parseDecimalNumber(raw);
  return num === null ? null : Math.round(num);
}

function detectCountryFromPostal(postalLine) {
  const value = String(postalLine || '').trim().toUpperCase();
  if (!value) return '';

  if (value.startsWith('DK')) return 'DK';
  if (value.startsWith('DE')) return 'DE';
  if (value.startsWith('NL')) return 'NL';
  if (value.startsWith('BE')) return 'BE';
  if (value.startsWith('D ')) return 'DE';

  if (/^\d{4}\s?[A-Z]{2}$/.test(value)) return 'NL';
  if (/^\d{5}$/.test(value)) return 'DE';
  if (/^\d{4}$/.test(value)) return 'DK';

  return '';
}

function parsePostalCityLine(line) {
  const value = normalizeInline(line);

  if (!value) {
    return { postal_code: '', city: '', country: '' };
  }

  let m = value.match(/^([A-Z]{1,2})\s+(\d{4,5})\s+(.+)$/i);
  if (m) {
    return {
      postal_code: m[2].trim(),
      city: m[3].trim(),
      country: m[1].toUpperCase() === 'D' ? 'DE' : m[1].toUpperCase()
    };
  }

  m = value.match(/^(\d{4,5})\s+(.+)$/i);
  if (m) {
    return {
      postal_code: m[1].trim(),
      city: m[2].trim(),
      country: detectCountryFromPostal(m[1])
    };
  }

  return {
    postal_code: '',
    city: value,
    country: ''
  };
}

function splitNameAddress(value) {
  const s = normalizeInline(value);
  if (!s) {
    return { name: '', address: '' };
  }

  // probeer laatste straat + huisnummer te pakken
  let m = s.match(/^(.*?)([A-Za-zÀ-ÿß0-9.\-\/,'() ]+\s+\d+(?:-\d+)?(?:,\s*\d+)?)$/);
  if (m) {
    const name = normalizeInline(m[1]);
    const address = normalizeInline(m[2]);
    if (name && address) {
      return { name, address };
    }
  }

  return { name: s, address: '' };
}

function mapTemperature(raw) {
  const s = normalizeInline(raw).toLowerCase();
  if (!s) return '';

  if (s.includes('?°c') || s === '?' || s === '?°') return '';

  if ((s.includes('frisch') || s.includes('fresh')) && (
    s.includes('0°c') || s.includes('0 c') || s.includes('1°c') || s.includes('2°c') || s.includes('3°c')
  )) {
    return 'Ultra Fresh (0°C / 3°C)';
  }

  if (s.includes('frisch') || s.includes('fresh')) {
    return 'Fresh (4°C / 7°C)';
  }

  if (s.includes('frozen') || s.includes('tiefkühl') || s.includes('-18')) {
    return 'Frozen (-18°C / -30°C)';
  }

  if (s.includes('thermo')) {
    return 'Thermo (8°C / 20°C)';
  }

  if (s.includes('ambient')) {
    return 'Ambient (Geen Temp)';
  }

  return '';
}

function isWetralogDocument(input, text) {
  const infoCreator = String(input.info?.Creator || '').toLowerCase();
  const infoProducer = String(input.info?.Producer || '').toLowerCase();
  const fullText = String(text || '').toLowerCase();

  return (
    fullText.includes('wetralog') ||
    fullText.includes('@wetralog.de') ||
    fullText.includes('transportauftrag') ||
    fullText.includes('ladestellen') ||
    fullText.includes('entladestellen') ||
    infoCreator.includes('crystal') ||
    infoProducer.includes('crystal')
  );
}

function splitPages(text) {
  const parts = String(text || '')
    .split(/(?=Seite\s+\d+\s+von\s+\d+)/gi)
    .map(p => p.trim())
    .filter(Boolean);

  return parts.length ? parts : [text];
}

function parseOrderNumber(pageText) {
  return (
    extractFirstMatch(pageText, /Transportauftrag\s*-\s*(\d+)/i) ||
    extractFirstMatch(pageText, /Transportauftrag[:\s-]+(\d+)/i) ||
    extractFirstMatch(pageText, /\bAuftrags(?:nr|nummer)?[:\s-]+(\d+)/i) ||
    ''
  );
}

function getSectionLines(pageText, startPatterns, endPatterns) {
  const starts = Array.isArray(startPatterns) ? startPatterns : [startPatterns];
  const ends = Array.isArray(endPatterns) ? endPatterns : [endPatterns];

  let startIndex = -1;
  let startLength = 0;

  for (const pattern of starts) {
    const regex = new RegExp(pattern, 'i');
    const m = regex.exec(pageText);
    if (m && (startIndex === -1 || m.index < startIndex)) {
      startIndex = m.index;
      startLength = m[0].length;
    }
  }

  if (startIndex === -1) return [];

  const remaining = pageText.slice(startIndex + startLength);
  let endIndex = remaining.length;

  for (const pattern of ends) {
    const regex = new RegExp(pattern, 'i');
    const m = regex.exec(remaining);
    if (m && m.index < endIndex) {
      endIndex = m.index;
    }
  }

  return remaining
    .slice(0, endIndex)
    .split('\n')
    .map(l => normalizeInline(l))
    .filter(Boolean);
}

function normalizePackagingName(raw) {
  const s = normalizeInline(raw).toUpperCase();
  if (!s) return 'EURO';

  if (s.includes('H1')) return 'H1';
  if (s.includes('EURO')) return 'EURO';
  if (s.includes('CHEP')) return 'CHEP';
  if (s.includes('DOLAV')) return 'WTLDOLAVHB';
  if (s.includes('EWP')) return 'EWP';

  return s;
}

function parseCombinedLocationLine(line) {
  // voorbeeld:
  // WFL Werk Coesfeld Stockum 2 D 48653 Coesfeld
  // Hilton Foods DK A/S Brunagervej 2-4 DK 8361 Aarhus
  const s = normalizeInline(line);

  let m = s.match(/^(.*)\s+([A-Z]{1,2})\s+(\d{4,5})\s+(.+)$/i);
  if (!m) {
    return {
      name: s,
      address: '',
      postal_code: '',
      city: '',
      country: ''
    };
  }

  const before = normalizeInline(m[1]);
  const countryPrefix = m[2].toUpperCase();
  const postal = m[3];
  const city = normalizeInline(m[4]);

  const split = splitNameAddress(before);

  return {
    name: ensureName(split.name || before),
    address: split.address || '',
    postal_code: postal,
    city,
    country: countryPrefix === 'D' ? 'DE' : countryPrefix
  };
}

function isDateLine(line) {
  return /^\d{2}\.\d{2}\.\d{4}$/.test(normalizeInline(line));
}

function isTimeLine(line) {
  return /^\d{2}:\d{2}\s*-\s*\d{2}:\d{2}$/.test(normalizeInline(line));
}

function isPickupHeaderLine(line) {
  const s = normalizeInline(line);
  return /^\d+\s+/.test(s) && /\s+[A-Z]{1,2}\s+\d{4,5}\s+/.test(s);
}

function isPickupGoodsLine(line) {
  const s = normalizeInline(line);
  return /^\d{6,10}\s+/.test(s) && /\bSP\b/i.test(s) && /\bkg\b/i.test(s);
}

function isDeliveryGoodsLine(line) {
  const s = normalizeInline(line);
  return /^\d{6,10}\s+Entladeeinheiten:/i.test(s);
}

function parsePickupGoodsLine(line) {
  const s = normalizeInline(line);

  // voorbeeld:
  // 81565124 H1EUROPAL 12 12,00 SP 4.643,20 kg Frisch 0°C
  const m = s.match(
    /^(\d{6,10})\s+([A-Z0-9_-]+)\s+(\d+(?:[.,]\d+)?)\s+(\d+(?:[.,]\d+)?)\s+SP\s+(\d+(?:\.\d{3})*,\d+)\s+kg(?:\s+(.+))?$/i
  );

  if (!m) return null;

  const reference = m[1];
  const packagingRaw = m[2];
  const quantity = parseIntNumber(m[3]) || 1;
  const palletSpaces = parseDecimalNumber(m[4]);
  const weight = parseDecimalNumber(m[5]) || 0;
  const tail = normalizeInline(m[6] || '');
  const mappedTemperature = mapTemperature(tail);

  return {
    reference,
    packagingRaw,
    packaging: normalizePackagingName(packagingRaw),
    quantity,
    total_pallet_spaces: palletSpaces,
    weight,
    temperatureRaw: tail,
    temperatureMapped: mappedTemperature
  };
}

function parseDeliveryGoodsLine(line) {
  const s = normalizeInline(line);

  // voorbeeld:
  // 81565124 Entladeeinheiten: 12 12,00 SP 4.643,20 kg
  const m = s.match(
    /^(\d{6,10})\s+Entladeeinheiten:\s+(\d+(?:[.,]\d+)?)\s+(\d+(?:[.,]\d+)?)\s+SP\s+(\d+(?:\.\d{3})*,\d+)\s+kg$/i
  );

  if (!m) return null;

  return {
    reference: m[1],
    quantity: parseIntNumber(m[2]) || 1,
    total_pallet_spaces: parseDecimalNumber(m[3]),
    weight: parseDecimalNumber(m[4]) || 0
  };
}

// ------------------------------------------------------------
// Pickup parsing
// ------------------------------------------------------------
function parsePickupSection(pageText) {
  const lines = getSectionLines(
    pageText,
    ['Ladestellen\\s*:'],
    ['Entladestellen\\s*:', 'Der beauftragte Unternehmer', 'ABRECHNUNG ERFOLGT', 'Mit freundlichen Grüßen']
  );

  const pickups = [];
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    if (isPickupHeaderLine(line)) {
      const seq = extractFirstMatch(line, /^(\d+)/);
      const locationRaw = normalizeInline(line.replace(/^\d+\s+/, ''));
      const location = parseCombinedLocationLine(locationRaw);

      let date = null;
      let time = '';
      let goods = [];

      let j = i + 1;

      // datum/tijd regel
      if (j < lines.length) {
        const dtLine = normalizeInline(lines[j]);

        // voorbeeld: 07.04.2026 15:00 - 15:00 .
        const dtMatch = dtLine.match(/^(\d{2}\.\d{2}\.\d{4})\s+(\d{2}:\d{2}\s*-\s*\d{2}:\d{2})/);
        if (dtMatch) {
          date = toIsoDate(dtMatch[1]);
          time = dtMatch[2];
          j++;
        }
      }

      // alle pickup-goodsregels pakken tot volgende pickupheader of einde sectie
      while (j < lines.length) {
        const current = normalizeInline(lines[j]);

        if (isPickupHeaderLine(current)) break;
        if (isPickupGoodsLine(current)) {
          const parsedGoods = parsePickupGoodsLine(current);
          if (parsedGoods) {
            goods.push(parsedGoods);
          }
        }

        j++;
      }

      pickups.push({
        seq,
        name: location.name,
        address: location.address,
        postal_code: location.postal_code,
        city: location.city,
        country: location.country,
        date,
        time,
        goods
      });

      i = j;
      continue;
    }

    i++;
  }

  return pickups;
}

// ------------------------------------------------------------
// Delivery parsing
// ------------------------------------------------------------
function parseDeliverySection(pageText) {
  const lines = getSectionLines(
    pageText,
    ['Entladestellen\\s*:'],
    ['Der beauftragte Unternehmer', 'ABRECHNUNG ERFOLGT', 'Mit freundlichen Grüßen']
  );

  const deliveries = [];
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    if (isPickupHeaderLine(line)) {
      const seq = extractFirstMatch(line, /^(\d+)/);
      const locationRaw = normalizeInline(line.replace(/^\d+\s+/, ''));
      const location = parseCombinedLocationLine(locationRaw);

      let date = null;
      let time = '';
      let reference = '';
      let quantity = null;
      let totalPalletSpaces = null;
      let weight = 0;

      let j = i + 1;

      if (j < lines.length) {
        const dtLine = normalizeInline(lines[j]);
        const dtMatch = dtLine.match(/^(\d{2}\.\d{2}\.\d{4})\s+(\d{2}:\d{2}\s*-\s*\d{2}:\d{2})/);
        if (dtMatch) {
          date = toIsoDate(dtMatch[1]);
          time = dtMatch[2];
          j++;
        }
      }

      if (j < lines.length && isDeliveryGoodsLine(lines[j])) {
        const parsedDelivery = parseDeliveryGoodsLine(lines[j]);
        if (parsedDelivery) {
          reference = parsedDelivery.reference;
          quantity = parsedDelivery.quantity;
          totalPalletSpaces = parsedDelivery.total_pallet_spaces;
          weight = parsedDelivery.weight;
          j++;
        }
      }

      deliveries.push({
        seq,
        name: location.name,
        address: location.address,
        postal_code: location.postal_code,
        city: location.city,
        country: location.country,
        date,
        time,
        reference,
        quantity,
        total_pallet_spaces: totalPalletSpaces,
        weight
      });

      i = j;
      continue;
    }

    i++;
  }

  return deliveries;
}

// ------------------------------------------------------------
// Build order
// ------------------------------------------------------------
function buildOrderJson(orderNumber, pickup, goods, delivery, pairedItem) {
  const packagingType = normalizePackagingName(goods.packaging || goods.packagingRaw || 'EURO');
  const mappedTemperature = goods.temperatureMapped || '';

  const quantity = goods.quantity || delivery.quantity || 1;
  const totalWeight = goods.weight || delivery.weight || 0;
  const palletSpaces = goods.total_pallet_spaces ?? delivery.total_pallet_spaces ?? null;

  const pickupNotes = [];
  if (pickup.time) {
    pickupNotes.push(`Laadtijd: ${pickup.time}`);
  }

  const deliveryNotes = [];
  if (delivery.time) {
    deliveryNotes.push(`Lostijd: ${delivery.time}`);
  }
  if (mappedTemperature) {
    deliveryNotes.push(`Temperatuur: ${mappedTemperature}`);
  }

  const customFields = {};
  if (mappedTemperature) {
    customFields.temperature1 = mappedTemperature;
  }

  const goodsObj = {
    quantity,
    description: packagingType,
    total_weight_kg: totalWeight,
    packaging_type: {
      name: packagingType
    },
    custom_fields: customFields
  };

  if (palletSpaces !== null && palletSpaces !== undefined) {
    goodsObj.total_pallet_spaces = palletSpaces;
  }

  return {
    json: {
      transport_service: {
        name: 'Transport',
        code: '1'
      },
      transport_network: {
        name: 'Agro World'
      },
      customer_reference_number: orderNumber,
      neutral_order_type: 'NO_NEUTRAL_ORDER',
      operation: 'CREATE',
      order_identifier: orderNumber,
      customer: {
        name: 'WETRALOG GmbH'
      },
      consignments: [
        {
          pickup_stop: {
            activity_label: 'PICKUP',
            note: pickupNotes.join(' | '),
            date: pickup.date,
            reference_number: goods.reference || orderNumber,
            location: {
              address: pickup.address || '',
              city: pickup.city || '',
              country: pickup.country || '',
              postal_code: pickup.postal_code || '',
              name: ensureName(pickup.name)
            }
          },
          delivery_stop: {
            activity_label: 'DELIVERY',
            note: deliveryNotes.join(' | '),
            date: delivery.date,
            reference_number: delivery.reference || goods.reference || orderNumber,
            location: {
              address: delivery.address || '',
              city: delivery.city || '',
              country: delivery.country || '',
              postal_code: delivery.postal_code || '',
              name: ensureName(delivery.name)
            }
          },
          goods: [goodsObj]
        }
      ],
      debug: {
        parser: 'wetralog_pdf_parser_v5_reference_match',
        order_number: orderNumber,
        pickup_seq: pickup.seq || '',
        delivery_seq: delivery.seq || '',
        goods_reference: goods.reference || '',
        delivery_reference: delivery.reference || '',
        quantity_found: quantity,
        weight_found: totalWeight,
        pallet_spaces_found: palletSpaces,
        packaging_found: packagingType,
        temperature_found: mappedTemperature || ''
      }
    },
    pairedItem
  };
}

// ------------------------------------------------------------
// Main loop
// ------------------------------------------------------------
for (const item of items) {
  const input = item.json || {};
  const rawText =
    input.text ||
    input.content ||
    input.raw_text ||
    input.extracted_text ||
    '';

  const text = safeText(rawText);

  if (!text) {
    results.push({
      json: {
        debug: {
          status: 'no_text',
          message: 'Geen tekst gevonden in input'
        }
      },
      pairedItem: item.pairedItem
    });
    continue;
  }

  if (!isWetralogDocument(input, text)) {
    results.push({
      json: {
        debug: {
          status: 'not_detected_as_wetralog',
          message: 'Document niet herkend als WETRALOG',
          preview: text.slice(0, 1200)
        }
      },
      pairedItem: item.pairedItem
    });
    continue;
  }

  const pages = splitPages(text);
  let itemCreated = 0;

  for (const pageText of pages) {
    const orderNumber = parseOrderNumber(pageText) || extractFirstMatch(pageText, /(\d{6,})/);
    const pickups = parsePickupSection(pageText);
    const deliveries = parseDeliverySection(pageText);

    if (!orderNumber || !pickups.length || !deliveries.length) {
      results.push({
        json: {
          debug: {
            status: 'partial_parse',
            order_number: orderNumber || '',
            pickups_found: pickups.length,
            deliveries_found: deliveries.length,
            preview: pageText.slice(0, 1500)
          }
        },
        pairedItem: item.pairedItem
      });
      continue;
    }

    const createdKeys = new Set();

    // hoofdlogica:
    // 1 pickup kan meerdere goods references hebben
    // elke goods reference koppelen aan delivery met dezelfde reference
    for (const pickup of pickups) {
      for (const goods of pickup.goods || []) {
        if (!goods.reference) continue;

        const matchingDeliveries = deliveries.filter(d => d.reference && d.reference === goods.reference);

        for (const delivery of matchingDeliveries) {
          const key = `${orderNumber}|${pickup.seq}|${goods.reference}|${delivery.seq}|${delivery.reference}`;
          if (createdKeys.has(key)) continue;
          createdKeys.add(key);

          results.push(
            buildOrderJson(orderNumber, pickup, goods, delivery, item.pairedItem)
          );
          itemCreated++;
        }
      }
    }

    // fallback:
    // 1 pickup + 1 goods + 1 delivery
    if (itemCreated === 0 && pickups.length === 1 && pickups[0].goods?.length === 1 && deliveries.length === 1) {
      results.push(
        buildOrderJson(orderNumber, pickups[0], pickups[0].goods[0], deliveries[0], item.pairedItem)
      );
      itemCreated++;
    }
  }

  if (itemCreated === 0) {
    results.push({
      json: {
        debug: {
          status: 'no_orders_created',
          message: 'Document herkend, maar geen orders opgebouwd',
          preview: text.slice(0, 1500)
        }
      },
      pairedItem: item.pairedItem
    });
  }
}

return results;
